const Sidebar = ({ isOpen, toggle }: { isOpen: boolean, toggle: () => void }) => {
  const location = useLocation();

  const menuItems = [
    { name: 'Dashboard', icon: LayoutDashboard, path: '/' },
    { name: 'Sales Entry', icon: ShoppingCart, path: '/sales' },
    { name: 'Products', icon: Package, path: '/products' },
    { name: 'Stock / Inventory', icon: History, path: '/stock' },
    { name: 'Customers / Dealers', icon: Users, path: '/customers' },
    { name: 'Sales Officers', icon: UserPlus, path: '/officers' },
    { name: 'Reports', icon: BarChart3, path: '/reports' },
  ];

  return (
    <div className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white transform ${isOpen ? 'translate-x-0' : '-translate-x-full'} transition-transform duration-300 md:relative md:translate-x-0`}>
      <div className="flex items-center justify-between p-4 border-b border-slate-800">
        <div className="flex items-center gap-2">
          <div className="p-2 bg-blue-600 rounded-lg">
            <CreditCard size={24} />
          </div>
          <span className="text-xl font-bold">MasterPro ERP</span>
        </div>
        <button className="md:hidden" onClick={toggle}><X size={24} /></button>
      </div>

      <nav className="p-4 space-y-2">
        {menuItems.map((item) => (
          <Link 
            key={item.path} 
            to={item.path}
            onClick={() => window.innerWidth < 768 && toggle()}
            className={`flex items-center gap-3 p-3 rounded-lg transition-colors ${location.pathname === item.path ? 'bg-blue-600' : 'hover:bg-slate-800'}`}
          >
            <item.icon size={20} />
            <span className="font-medium">{item.name}</span>
          </Link>
        ))}
      </nav>

      <div className="absolute bottom-0 w-full p-4 border-t border-slate-800">
        <button className="flex items-center gap-3 p-3 w-full hover:bg-slate-800 rounded-lg transition-colors">
          <LogOut size={20} />
          <span className="font-medium">Sign Out</span>
        </button>
      </div>
    </div>
  );
};

export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // App-wide state
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('erp_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('erp_customers');
    return saved ? JSON.parse(saved) : INITIAL_CUSTOMERS;
  });

  const [officers, setOfficers] = useState<Officer[]>(() => {
    const saved = localStorage.getItem('erp_officers');
    return saved ? JSON.parse(saved) : INITIAL_OFFICERS;
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem('erp_sales');
    return saved ? JSON.parse(saved) : [];
  });

  // Sync state to local storage
  useEffect(() => {
    localStorage.setItem('erp_products', JSON.stringify(products));
    localStorage.setItem('erp_customers', JSON.stringify(customers));
    localStorage.setItem('erp_officers', JSON.stringify(officers));
    localStorage.setItem('erp_sales', JSON.stringify(sales));
  }, [products, customers, officers, sales]);

  const addSale = (newSale: Sale) => {
    setSales(prev => [...prev, newSale]);
    // Deduct stock
    setProducts(prev => prev.map(p => {
      const soldItem = newSale.items.find(si => si.productCode === p.code);
      if (soldItem) {
        return { ...p, stock: p.stock - soldItem.quantity };
      }
      return p;
    }));
    // Update customer balance if credit/partial
    if (newSale.dueAmount > 0) {
      setCustomers(prev => prev.map(c => {
        if (c.id === newSale.customerId) {
          return { ...c, balance: c.balance - newSale.dueAmount };
        }
        return c;
      }));
    }
  };

  return (
    <HashRouter>
      <div className="flex min-h-screen bg-slate-50">
        <Sidebar isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} />

        <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
          <header className="h-16 flex items-center justify-between px-6 bg-white border-b border-slate-200">
            <button className="md:hidden p-2 text-slate-600" onClick={() => setSidebarOpen(true)}>
              <Menu size={24} />
            </button>
            <div className="hidden md:block">
              <h2 className="text-lg font-semibold text-slate-800 uppercase tracking-tight">Enterprise Resource Planning</h2>
            </div>
            <div className="flex items-center gap-4">
              <div className="text-right hidden sm:block">
                <p className="text-sm font-bold text-slate-900 leading-tight">Admin User</p>
                <p className="text-xs text-slate-500">Super Administrator</p>
              </div>
              <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold border-2 border-white shadow-sm">
                AD
              </div>
            </div>
          </header>

          <main className="flex-1 overflow-y-auto p-4 md:p-8">
            <Routes>
              <Route path="/" element={<Dashboard products={products} sales={sales} customers={customers} />} />
              <Route path="/sales" element={
                <SalesEntry 
                  products={products} 
                  customers={customers} 
                  officers={officers} 
                  onAddSale={addSale} 
                />
              } />
              <Route path="/products" element={<ProductList products={products} setProducts={setProducts} />} />
              <Route path="/stock" element={<StockManagement products={products} setProducts={setProducts} />} />
              <Route path="/customers" element={<CustomerList customers={customers} setCustomers={setCustomers} />} />
              <Route path="/officers" element={<OfficerList officers={officers} setOfficers={setOfficers} />} />
              <Route path="/reports" element={<Reports sales={sales} products={products} officers={officers} customers={customers} />} />
            </Routes>
          </main>
        </div>
      </div>
    </HashRouter>
  );
}

