import React, { useState } from 'react';
import { Product } from '../types';
import { PlusCircle, MinusCircle, History, PackageCheck, AlertTriangle } from 'lucide-react';

interface StockManagementProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
}

const StockManagement: React.FC<StockManagementProps> = ({ products, setProducts }) => {
  const [selectedProductCode, setSelectedProductCode] = useState('');
  const [quantity, setQuantity] = useState(0);
  const [adjustmentType, setAdjustmentType] = useState<'IN' | 'OUT'>('IN');

  const selectedProduct = products.find(p => p.code === selectedProductCode);

  const handleAdjust = () => {
    if (!selectedProductCode || quantity <= 0) {
      alert("Invalid selection or quantity");
      return;
    }

    setProducts(prev => prev.map(p => {
      if (p.code === selectedProductCode) {
        const newStock = adjustmentType === 'IN' ? p.stock + quantity : p.stock - quantity;
        if (newStock < 0) {
          alert("Insufficient stock for deduction!");
          return p;
        }
        return { ...p, stock: newStock };
      }
      return p;
    }));

    alert(`Stock adjusted for ${selectedProduct?.name}`);
    setQuantity(0);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-3 mb-2">
        <PackageCheck className="text-blue-600" size={32} />
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Inventory Control</h1>
          <p className="text-slate-500 text-sm">Manage stock inflows and manual adjustments</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
              Manual Stock Adjustment
            </h3>
            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-slate-400 uppercase">Select Product</label>
                <select 
                  className="w-full mt-1 border rounded-lg p-2.5 bg-slate-50 outline-none"
                  value={selectedProductCode}
                  onChange={(e) => setSelectedProductCode(e.target.value)}
                >
                  <option value="">Choose a product...</option>
                  {products.map(p => (
                    <option key={p.code} value={p.code}>{p.code} - {p.name}</option>
                  ))}
                </select>
              </div>

              {selectedProduct && (
                <div className="p-3 bg-blue-50 border border-blue-100 rounded-lg">
                  <p className="text-xs text-blue-600 font-bold uppercase">Current Stock</p>
                  <p className="text-xl font-black text-blue-900">{selectedProduct.stock} {selectedProduct.unit}s</p>
                </div>
              )}

              <div>
                <label className="text-xs font-bold text-slate-400 uppercase">Adjustment Type</label>
                <div className="grid grid-cols-2 gap-2 mt-1">
                  <button 
                    onClick={() => setAdjustmentType('IN')}
                    className={`flex items-center justify-center gap-2 py-2 rounded-lg font-bold border ${adjustmentType === 'IN' ? 'bg-emerald-50 border-emerald-500 text-emerald-700' : 'bg-slate-50 border-slate-200 text-slate-500'}`}
                  >
                    <PlusCircle size={18} /> STOCK IN
                  </button>
                  <button 
                    onClick={() => setAdjustmentType('OUT')}
                    className={`flex items-center justify-center gap-2 py-2 rounded-lg font-bold border ${adjustmentType === 'OUT' ? 'bg-red-50 border-red-500 text-red-700' : 'bg-slate-50 border-slate-200 text-slate-500'}`}
                  >
                    <MinusCircle size={18} /> STOCK OUT
                  </button>
                </div>
              </div>

              <div>
                <label className="text-xs font-bold text-slate-400 uppercase">Quantity ({selectedProduct?.unit || 'Units'})</label>
                <input 
                  type="number" 
                  value={quantity} 
                  onChange={(e) => setQuantity(parseInt(e.target.value) || 0)}
                  className="w-full mt-1 border rounded-lg p-3 text-lg font-bold outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="0"
                />
              </div>

              <button 
                onClick={handleAdjust}
                disabled={!selectedProduct}
                className="w-full bg-slate-900 text-white font-bold py-3 rounded-xl hover:bg-slate-800 disabled:opacity-50 transition-colors shadow-lg shadow-slate-200"
              >
                APPLY ADJUSTMENT
              </button>
            </div>
          </div>
        </div>

        <div className="lg:col-span-2">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 min-h-full">
            <h3 className="font-bold text-slate-800 mb-6 flex items-center justify-between">
              <span>Inventory Status Overview</span>
              <span className="flex items-center gap-1.5 text-xs font-bold text-amber-600 bg-amber-50 px-3 py-1 rounded-full border border-amber-100">
                <AlertTriangle size={12} /> Low Stock Warnings
              </span>
            </h3>

            <div className="space-y-4">
              {products.filter(p => p.stock < 20).map(p => (
                <div key={p.code} className="flex items-center justify-between p-4 bg-red-50 border border-red-100 rounded-xl">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-white rounded shadow-sm text-red-600"><AlertTriangle size={20} /></div>
                    <div>
                      <p className="font-bold text-slate-900">{p.name}</p>
                      <p className="text-xs font-bold text-slate-400">CODE: {p.code}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-sm font-black text-red-700">{p.stock} BAGS LEFT</p>
                    <button className="text-[10px] font-black text-red-500 uppercase hover:underline">Quick Restock</button>
                  </div>
                </div>
              ))}
              {products.filter(p => p.stock >= 20).map(p => (
                <div key={p.code} className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-xl opacity-70">
                  <div>
                    <p className="font-semibold text-slate-700">{p.name}</p>
                    <p className="text-xs text-slate-500">CODE: {p.code}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-sm font-bold text-slate-600">{p.stock} BAGS</p>
                    <p className="text-[10px] text-green-600 font-bold uppercase">Optimal</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StockManagement;

import React, { useState, useEffect } from 'react';
// Added Package to the import list from lucide-react
import { Plus, Trash2, Save, Printer, User, Search, Tag, ShoppingCart, Package } from 'lucide-react';
import { Product, Customer, Officer, Sale, SaleItem } from '../types';

interface SalesEntryProps {
  products: Product[];
  customers: Customer[];
  officers: Officer[];
  onAddSale: (sale: Sale) => void;
}

const SalesEntry: React.FC<SalesEntryProps> = ({ products, customers, officers, onAddSale }) => {
  const [invoiceNo, setInvoiceNo] = useState(() => Math.floor(100000 + Math.random() * 900000).toString());
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [serialNo, setSerialNo] = useState('1');

  const [selectedOfficerId, setSelectedOfficerId] = useState('');
  const [selectedCustomerId, setSelectedCustomerId] = useState('');

  const [currentCustomer, setCurrentCustomer] = useState<Customer | null>(null);
  const [currentOfficer, setCurrentOfficer] = useState<Officer | null>(null);

  const [items, setItems] = useState<SaleItem[]>([]);
  const [discount, setDiscount] = useState(0);
  const [paidAmount, setPaidAmount] = useState(0);

  // Quick Search state
  const [productSearchCode, setProductSearchCode] = useState('');
  const [customerSearchId, setCustomerSearchId] = useState('');
  const [officerSearchId, setOfficerSearchId] = useState('');

  // Auto-fetch Customer
  const fetchCustomer = (id: string) => {
    const found = customers.find(c => c.id.toLowerCase() === id.toLowerCase());
    if (found) {
      setCurrentCustomer(found);
      setSelectedCustomerId(found.id);
    } else {
      setCurrentCustomer(null);
    }
  };

  // Auto-fetch Officer
  const fetchOfficer = (id: string) => {
    const found = officers.find(o => o.id.toLowerCase() === id.toLowerCase());
    if (found) {
      setCurrentOfficer(found);
      setSelectedOfficerId(found.id);
    } else {
      setCurrentOfficer(null);
    }
  };

  // Auto-fetch and add Product to items
  const handleProductSearch = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      const found = products.find(p => p.code === productSearchCode);
      if (found) {
        if (found.stock <= 0) {
          alert("Out of stock!");
          return;
        }
        const existingItem = items.find(i => i.productCode === found.code);
        if (existingItem) {
          setItems(items.map(i => i.productCode === found.code ? { ...i, quantity: i.quantity + 1, total: (i.quantity + 1) * i.unitPrice } : i));
        } else {
          setItems([...items, {
            productCode: found.code,
            productName: found.name,
            quantity: 1,
            unitPrice: found.tpPrice,
            total: found.tpPrice
          }]);
        }
        setProductSearchCode('');
      } else {
        alert("Product Code not found");
      }
    }
  };

  const removeItem = (index: number) => {
    setItems(items.filter((_, i) => i !== index));
  };

  const updateItemQty = (index: number, qty: number) => {
    const newItems = [...items];
    newItems[index].quantity = qty;
    newItems[index].total = qty * newItems[index].unitPrice;
    setItems(newItems);
  };

  const totalAmount = items.reduce((sum, i) => sum + i.total, 0);
  const netAmount = totalAmount - discount;
  const dueAmount = netAmount - paidAmount;

  const handleSave = () => {
    if (!currentCustomer || !currentOfficer || items.length === 0) {
      alert("Please ensure Customer, Officer and at least one item are selected.");
      return;
    }

    const sale: Sale = {
      invoiceNo,
      date,
      serialNo,
      officerId: currentOfficer.id,
      customerId: currentCustomer.id,
      items,
      totalAmount,
      discount,
      netAmount,
      paidAmount,
      dueAmount,
      paymentMethod: paidAmount === 0 ? 'Credit' : (paidAmount === netAmount ? 'Cash' : 'Partial')
    };

    onAddSale(sale);
    alert("Sale registered successfully!");
    // Reset form
    setItems([]);
    setDiscount(0);
    setPaidAmount(0);
    setInvoiceNo(Math.floor(100000 + Math.random() * 900000).toString());
    setCurrentCustomer(null);
    setCustomerSearchId('');
    setOfficerSearchId('');
    setCurrentOfficer(null);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
          <ShoppingCart className="text-blue-600" /> New Sales Invoice
        </h1>
        <div className="flex gap-2">
           <button className="bg-slate-200 hover:bg-slate-300 text-slate-700 px-4 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors">
            <Printer size={18} /> Print Draft
          </button>
          <button onClick={handleSave} className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg font-medium flex items-center gap-2 transition-colors shadow-sm">
            <Save size={18} /> Complete Invoice
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Side: Basic Info & Customer */}
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Tag size={18} className="text-blue-500" /> Invoice Header
            </h3>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-xs font-semibold text-slate-500 uppercase">Invoice No</label>
                <input type="text" value={invoiceNo} readOnly className="w-full mt-1 bg-slate-50 border border-slate-200 rounded-lg p-2 font-mono text-blue-600" />
              </div>
              <div>
                <label className="text-xs font-semibold text-slate-500 uppercase">Date</label>
                <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="w-full mt-1 border border-slate-200 rounded-lg p-2" />
              </div>
              <div className="col-span-2">
                <label className="text-xs font-semibold text-slate-500 uppercase">Serial Number</label>
                <input type="text" value={serialNo} onChange={(e) => setSerialNo(e.target.value)} className="w-full mt-1 border border-slate-200 rounded-lg p-2" placeholder="e.g. 001/A" />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
              <User size={18} className="text-emerald-500" /> Customer & Officer
            </h3>
            <div className="space-y-4">
              <div>
                <label className="text-xs font-semibold text-slate-500 uppercase">Officer Code/ID</label>
                <div className="relative">
                  <input 
                    type="text" 
                    value={officerSearchId}
                    onChange={(e) => {setOfficerSearchId(e.target.value); fetchOfficer(e.target.value);}}
                    className="w-full mt-1 border border-slate-200 rounded-lg p-2 pl-10" 
                    placeholder="Enter Officer ID (e.g. O001)" 
                  />
                  <Search className="absolute left-3 top-3.5 text-slate-400" size={16} />
                </div>
                {currentOfficer && (
                  <div className="mt-2 p-2 bg-blue-50 rounded text-sm text-blue-700">
                    <p className="font-bold">{currentOfficer.name}</p>
                    <p className="text-xs">Area: {currentOfficer.area}</p>
                  </div>
                )}
              </div>

              <div>
                <label className="text-xs font-semibold text-slate-500 uppercase">Customer Code/ID</label>
                <div className="relative">
                  <input 
                    type="text" 
                    value={customerSearchId}
                    onChange={(e) => {setCustomerSearchId(e.target.value); fetchCustomer(e.target.value);}}
                    className="w-full mt-1 border border-slate-200 rounded-lg p-2 pl-10" 
                    placeholder="Enter Dealer ID (e.g. C001)" 
                  />
