export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(() => localStorage.getItem('erp_logged_in') === 'true');
  const [lang, setLang] = useState<Lang>(() => (localStorage.getItem('erp_lang') as Lang) || 'BN');

  const t = (key: string) => translations[lang][key] || key;
  const companyName = t('companyLabel');

  // App-wide state
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('erp_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('erp_customers');
    return saved ? JSON.parse(saved) : INITIAL_CUSTOMERS;
  });

  const [officers, setOfficers] = useState<Officer[]>(() => {
    const saved = localStorage.getItem('erp_officers');
    return saved ? JSON.parse(saved) : INITIAL_OFFICERS;
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem('erp_sales');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('erp_products', JSON.stringify(products));
    localStorage.setItem('erp_customers', JSON.stringify(customers));
    localStorage.setItem('erp_officers', JSON.stringify(officers));
    localStorage.setItem('erp_sales', JSON.stringify(sales));
    localStorage.setItem('erp_lang', lang);
  }, [products, customers, officers, sales, lang]);

  const handleLogin = () => {
    setIsLoggedIn(true);
    localStorage.setItem('erp_logged_in', 'true');
  };

  const addSale = (newSale: Sale) => {
    setSales(prev => [...prev, newSale]);
    setProducts(prev => prev.map(p => {
      const soldItem = newSale.items.find(si => si.productCode === p.code);
      if (soldItem) return { ...p, stock: p.stock - soldItem.quantity };
      return p;
    }));
    if (newSale.dueAmount > 0) {
      setCustomers(prev => prev.map(c => {
        if (c.id === newSale.customerId) return { ...c, balance: c.balance - newSale.dueAmount };
        return c;
      }));
    }
  };

  if (!isLoggedIn) {
    return (
      <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
        <LoginPage onLogin={handleLogin} />
      </LanguageContext.Provider>
    );
  }

  return (
    <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
      <HashRouter>
        <div className="flex min-h-screen bg-slate-50">
          <Sidebar isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} />

          <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
            <header className="h-20 flex items-center justify-between px-8 bg-white border-b border-slate-200">
              <div className="flex items-center gap-4">
                <button className="md:hidden p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors" onClick={() => setSidebarOpen(true)}>
                  <Menu size={24} />
                </button>
                <div className="hidden md:block">
                  <h2 className="text-xl font-black text-slate-900 tracking-tight">{companyName}</h2>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">{t('admin')}</p>
                </div>
              </div>

              <div className="flex items-center gap-6">
                <button 
                  onClick={() => setLang(lang === 'EN' ? 'BN' : 'EN')}
                  className="flex items-center gap-2 bg-slate-900 text-white px-5 py-2.5 rounded-2xl text-xs font-black transition-all hover:bg-slate-800 shadow-lg shadow-slate-200 active:scale-95"
                >
                  <Languages size={18} />
                  <span>{t('toggleLang')}</span>
                </button>

                <div className="flex items-center gap-4 pl-6 border-l border-slate-200">
                  <div className="text-right hidden sm:block">
                    <p className="text-sm font-black text-slate-900 leading-none mb-1">Administrator</p>
                    <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-wider flex items-center justify-end gap-1">
                      <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span> Online
                    </p>
                  </div>
                  <div className="w-12 h-12 rounded-2xl bg-blue-100 flex items-center justify-center text-blue-600 font-black border-2 border-white shadow-inner">
                    AD
                  </div>
                </div>
              </div>
            </header>

            <main className="flex-1 overflow-y-auto p-6 md:p-10">
              <Routes>
                <Route path="/" element={<Dashboard products={products} sales={sales} customers={customers} />} />
                <Route path="/sales" element={<SalesEntry products={products} customers={customers} officers={officers} onAddSale={addSale} />} />
                <Route path="/products" element={<ProductList products={products} setProducts={setProducts} />} />
                <Route path="/stock" element={<StockManagement products={products} setProducts={setProducts} />} />
                <Route path="/customers" element={<CustomerList customers={customers} setCustomers={setCustomers} />} />
                <Route path="/officers" element={<OfficerList officers={officers} setOfficers={setOfficers} />} />
                <Route path="/reports" element={<Reports sales={sales} products={products} officers={officers} customers={customers} />} />
                <Route path="*" element={<Navigate to="/" />} />
              </Routes>
            </main>
          </div>
        </div>
      </HashRouter>
    </LanguageContext.Provider>
  );
}

