export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(() => localStorage.getItem('erp_logged_in') === 'true');
  const [lang, setLang] = useState<Lang>(() => (localStorage.getItem('erp_lang') as Lang) || 'BN');

  const t = (key: string) => translations[lang][key] || key;
  const companyName = t('companyLabel');

  // App-wide state
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('erp_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('erp_customers');
    return saved ? JSON.parse(saved) : INITIAL_CUSTOMERS;
  });

  const [officers, setOfficers] = useState<Officer[]>(() => {
    const saved = localStorage.getItem('erp_officers');
    return saved ? JSON.parse(saved) : INITIAL_OFFICERS;
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem('erp_sales');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('erp_products', JSON.stringify(products));
    localStorage.setItem('erp_customers', JSON.stringify(customers));
    localStorage.setItem('erp_officers', JSON.stringify(officers));
    localStorage.setItem('erp_sales', JSON.stringify(sales));
    localStorage.setItem('erp_lang', lang);
  }, [products, customers, officers, sales, lang]);

  const handleLogin = () => {
    setIsLoggedIn(true);
    localStorage.setItem('erp_logged_in', 'true');
  };

  const addSale = (newSale: Sale) => {
    setSales(prev => [...prev, newSale]);
    setProducts(prev => prev.map(p => {
      const soldItem = newSale.items.find(si => si.productCode === p.code);
      if (soldItem) return { ...p, stock: p.stock - soldItem.quantity };
      return p;
    }));
    if (newSale.dueAmount > 0) {
      setCustomers(prev => prev.map(c => {
        if (c.id === newSale.customerId) return { ...c, balance: c.balance - newSale.dueAmount };
        return c;
      }));
    }
  };

  if (!isLoggedIn) {
    return (
      <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
        <LoginPage onLogin={handleLogin} />
      </LanguageContext.Provider>
    );
  }

  return (
    <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
      <HashRouter>
        <div className="flex min-h-screen bg-slate-50">
          <Sidebar isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} />

          <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
            <header className="h-20 flex items-center justify-between px-8 bg-white border-b border-slate-200">
              <div className="flex items-center gap-4">
                <button className="md:hidden p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors" onClick={() => setSidebarOpen(true)}>
                  <Menu size={24} />
                </button>
                <div className="hidden md:block">
                  <h2 className="text-xl font-black text-[#722f37] tracking-tight">{companyName}</h2>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">{t('admin')}</p>
                </div>
              </div>

              <div className="flex items-center gap-6">
                <button 
                  onClick={() => setLang(lang === 'EN' ? 'BN' : 'EN')}
                  className="flex items-center gap-2 bg-[#722f37] text-white px-5 py-2.5 rounded-2xl text-xs font-black transition-all hover:bg-[#5a252c] shadow-lg shadow-rose-900/20 active:scale-95"
                >
                  <Languages size={18} />
                  <span>{t('toggleLang')}</span>
                </button>

                <div className="flex items-center gap-4 pl-6 border-l border-slate-200">
                  <div className="text-right hidden sm:block">
                    <p className="text-sm font-black text-slate-900 leading-none mb-1">Administrator</p>
                    <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-wider flex items-center justify-end gap-1">
                      <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span> Online
                    </p>
                  </div>
                  <div className="w-12 h-12 rounded-2xl bg-rose-50 flex items-center justify-center text-[#722f37] font-black border-2 border-white shadow-inner">
                    AD
                  </div>
                </div>
              </div>
            </header>

            <main className="flex-1 overflow-y-auto p-6 md:p-10">
              <Routes>
                <Route path="/" element={<Dashboard products={products} sales={sales} customers={customers} />} />
                <Route path="/sales" element={<SalesEntry products={products} customers={customers} officers={officers} onAddSale={addSale} />} />
                <Route path="/products" element={<ProductList products={products} setProducts={setProducts} />} />
                <Route path="/stock" element={<StockManagement products={products} setProducts={setProducts} />} />
                <Route path="/customers" element={<CustomerList customers={customers} setCustomers={setCustomers} />} />
                <Route path="/officers" element={<OfficerList officers={officers} setOfficers={setOfficers} />} />
                <Route path="/reports" element={<Reports sales={sales} products={products} officers={officers} customers={customers} />} />
                <Route path="*" element={<Navigate to="/" />} />
              </Routes>
            </main>
          </div>
        </div>
      </HashRouter>
    </LanguageContext.Provider>
  );
}

import React, { useState, useContext } from 'react';
import { Trash2, Save, User, Search, Tag, ShoppingCart, Package, Info, FileText, CheckCircle2 } from 'lucide-react';
import { Product, Customer, Officer, Sale, SaleItem } from '../types';
import { LanguageContext } from '../App';

interface SalesEntryProps {
  products: Product[];
  customers: Customer[];
  officers: Officer[];
  onAddSale: (sale: Sale) => void;
}

const SalesEntry: React.FC<SalesEntryProps> = ({ products, customers, officers, onAddSale }) => {
  const langContext = useContext(LanguageContext);
  const { t, lang } = langContext!;

  const [invoiceNo, setInvoiceNo] = useState(() => Math.floor(100000 + Math.random() * 900000).toString());
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [serialNo, setSerialNo] = useState('1');

  const [currentCustomer, setCurrentCustomer] = useState<Customer | null>(null);
  const [currentOfficer, setCurrentOfficer] = useState<Officer | null>(null);

  const [items, setItems] = useState<SaleItem[]>([]);
  const [discount, setDiscount] = useState(0);
  const [paidAmount, setPaidAmount] = useState(0);

  const [priceType, setPriceType] = useState<'tp' | 'mrp' | 'sp'>('tp');
  const [productSearchCode, setProductSearchCode] = useState('');
  const [customerSearchId, setCustomerSearchId] = useState('');
  const [officerSearchId, setOfficerSearchId] = useState('');

  const [showInvoiceReport, setShowInvoiceReport] = useState<Sale | null>(null);

  const fetchCustomer = (id: string) => {
    const found = customers.find(c => c.id.toLowerCase() === id.toLowerCase());
    setCurrentCustomer(found || null);
  };

  const fetchOfficer = (id: string) => {
    const found = officers.find(o => o.id.toLowerCase() === id.toLowerCase());
    setCurrentOfficer(found || null);
  };

  const handleProductSearch = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      const found = products.find(p => p.code === productSearchCode);
      if (found) {
        if (found.stock <= 0) {
          alert(lang === 'BN' ? "স্টক শেষ!" : "Out of stock!");
          return;
        }

        let price = found.tpPrice;
        if (priceType === 'mrp') price = found.mrpPrice;
        if (priceType === 'sp') price = found.spPrice || found.tpPrice;

        const existingItem = items.find(i => i.productCode === found.code);
        if (existingItem) {
          setItems(items.map(i => i.productCode === found.code ? { ...i, quantity: i.quantity + 1, total: (i.quantity + 1) * i.unitPrice } : i));
        } else {
          setItems([...items, {
            productCode: found.code,
            productName: found.name,
            quantity: 1,
            unitPrice: price,
            total: price
          }]);
        }
        setProductSearchCode('');
      } else {
        alert(lang === 'BN' ? "প্রোডাক্ট কোড পাওয়া যায়নি" : "Product Code not found");
      }
    }
  };

  const removeItem = (index: number) => setItems(items.filter((_, i) => i !== index));

  const updateItemQty = (index: number, qty: number) => {
    const newItems = [...items];
    newItems[index].quantity = qty;
    newItems[index].total = qty * newItems[index].unitPrice;
    setItems(newItems);
  };

  const totalAmount = items.reduce((sum, i) => sum + i.total, 0);
  const netAmount = totalAmount - discount;
  const dueAmount = netAmount - paidAmount;

  const handleSave = () => {
    if (!currentCustomer || !currentOfficer || items.length === 0) {
      alert(lang === 'BN' ? "কাস্টমার, অফিসার এবং কমপক্ষে একটি প্রোডাক্ট নির্বাচন করুন।" : "Please ensure Customer, Officer and at least one item are selected.");
      return;
    }

    const sale: Sale = {
      invoiceNo,
      date,
      serialNo,
      officerId: currentOfficer.id,
      customerId: currentCustomer.id,
      items,
      totalAmount,
      discount,
      netAmount,
      paidAmount,
      dueAmount,
      paymentMethod: paidAmount === 0 ? 'Credit' : (paidAmount === netAmount ? 'Cash' : 'Partial')
    };

    onAddSale(sale);
    setShowInvoiceReport(sale);

    // Reset form after saving
    setItems([]);
    setDiscount(0);
    setPaidAmount(0);
    setInvoiceNo(Math.floor(100000 + Math.random() * 900000).toString());
    setCurrentCustomer(null);
    setCurrentOfficer(null);
    setCustomerSearchId('');
    setOfficerSearchId('');
  };

  if (showInvoiceReport) {
    const cust = customers.find(c => c.id === showInvoiceReport.customerId);
    const off = officers.find(o => o.id === showInvoiceReport.officerId);

    return (
      <div className="max-w-4xl mx-auto bg-white rounded-3xl shadow-2xl overflow-hidden border border-slate-200">
        <div className="bg-slate-900 p-10 text-white flex justify-between items-center">
          <div>
            <h2 className="text-3xl font-black tracking-tight">{lang === 'BN' ? 'বিক্রয় চালান' : 'Sales Invoice Report'}</h2>
            <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Invoice #{showInvoiceReport.invoiceNo}</p>
          </div>
          <CheckCircle2 size={48} className="text-emerald-500" />
        </div>

        <div className="p-10 space-y-10">
          <div className="grid grid-cols-2 gap-10 border-b border-slate-100 pb-10">
            <div className="space-y-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{lang === 'BN' ? 'কাস্টমার তথ্য' : 'Customer Info'}</p>
              <div>
                <p className="text-xl font-black text-slate-900">{cust?.name}</p>
                <p className="text-slate-500 font-bold">{cust?.companyName}</p>
                <p className="text-slate-400 text-sm">{cust?.address}</p>
                <p className="text-[#722f37] font-bold mt-1">{cust?.mobile}</p>
              </div>
            </div>
            <div className="space-y-4 text-right">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{lang === 'BN' ? 'চালান তথ্য' : 'Invoice Info'}</p>
