import React, { useState, useContext } from 'react';
import { Product } from '../types';
import { Search, Filter, Plus, Edit2, Trash2, X, Package, Tag } from 'lucide-react';
import { LanguageContext } from '../App';

interface ProductListProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
}

const ProductList: React.FC<ProductListProps> = ({ products, setProducts }) => {
  const { t, lang } = useContext(LanguageContext)!;
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState('All');
  const [showModal, setShowModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  // Form State
  const [formData, setFormData] = useState<Partial<Product>>({
    status: 'Active',
    unit: 'Bag',
    stock: 0,
    mrpPrice: 0,
    tpPrice: 0,
    spPrice: 0,
    purchasePrice: 0
  });

  const categories = ['All', 'Poultry Feed', 'Fish Feed', 'Cattle Feed'];

  const handleOpenModal = (p?: Product) => {
    if (p) {
      setEditingProduct(p);
      setFormData(p);
    } else {
      setEditingProduct(null);
      setFormData({
        code: '', name: '', category: 'Poultry Feed', unit: 'Bag', bagSize: '50 kg',
        purchasePrice: 0, tpPrice: 0, mrpPrice: 0, spPrice: 0, stock: 0, status: 'Active'
      });
    }
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.code || !formData.name) return;

    if (editingProduct) {
      setProducts(prev => prev.map(p => p.code === editingProduct.code ? { ...p, ...formData as Product } : p));
    } else {
      if (products.some(p => p.code === formData.code)) {
        alert(lang === 'BN' ? "এই কোডটি ইতিমধ্যে ব্যবহৃত হয়েছে" : "Code already exists");
        return;
      }
      setProducts(prev => [...prev, formData as Product]);
    }
    setShowModal(false);
  };

  const filtered = products.filter(p => {
    const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.code.includes(searchTerm);
    const matchesCategory = filterCategory === 'All' || p.category === filterCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">{lang === 'BN' ? 'পণ্য তালিকা' : 'Product Inventory'}</h1>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Pricing & Stock Management</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="bg-[#722f37] text-white px-8 py-4 rounded-2xl font-black flex items-center justify-center gap-3 shadow-xl shadow-rose-900/20 hover:bg-[#5a252c] transition-all active:scale-95 text-sm uppercase tracking-widest"
        >
          <Plus size={20} /> {lang === 'BN' ? 'নতুন পণ্য' : 'New Product'}
        </button>
      </div>

      <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-200 flex flex-col md:flex-row gap-4 items-center">
        <div className="relative flex-1 w-full">
          <input 
            type="text" 
            placeholder={lang === 'BN' ? "কোড বা নাম দিয়ে খুজুন..." : "Search by code or name..."} 
            className="w-full pl-14 pr-4 py-4 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-rose-800 bg-slate-50/50 font-bold text-slate-700 transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <Search className="absolute left-5 top-4.5 text-slate-300" size={20} />
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          <select 
            className="flex-1 md:w-56 border border-slate-100 rounded-2xl px-5 py-4 bg-slate-50/50 font-black text-slate-600 outline-none transition-all uppercase text-[10px] tracking-widest"
            value={filterCategory}
            onChange={(e) => setFilterCategory(e.target.value)}
          >
            {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
          </select>
          <button className="p-4 border border-slate-100 rounded-2xl bg-slate-50/50 text-slate-400 hover:bg-slate-100 hover:text-slate-900 transition-all">
            <Filter size={24} />
          </button>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden">
