          <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-200">
            <h3 className="font-black text-slate-800 mb-8 uppercase text-xs tracking-widest">
              Manual Stock Adjustment
            </h3>
            <div className="space-y-5">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Select Product</label>
                <select 
                  className="w-full mt-1 border rounded-2xl p-4 bg-slate-50 font-bold text-slate-700 outline-none focus:ring-2 focus:ring-[#722f37]"
                  value={selectedProductCode}
                  onChange={(e) => setSelectedProductCode(e.target.value)}
                >
                  <option value="">Choose a product...</option>
                  {products.map(p => (
                    <option key={p.code} value={p.code}>{p.code} - {p.name}</option>
                  ))}
                </select>
              </div>

              {selectedProduct && (
                <div className="p-4 bg-rose-50 border border-rose-100 rounded-2xl">
