import React, { useState, useContext } from 'react';
import { Trash2, Save, User, Search, Tag, ShoppingCart, Package, Info, FileText, CheckCircle2, Hash } from 'lucide-react';
import { Product, Customer, Officer, Sale, SaleItem } from '../types';
import { LanguageContext } from '../App';

interface SalesEntryProps {
  products: Product[];
  customers: Customer[];
  officers: Officer[];
  onAddSale: (sale: Sale) => void;
}

const SalesEntry: React.FC<SalesEntryProps> = ({ products, customers, officers, onAddSale }) => {
  const { t, lang } = useContext(LanguageContext)!;

  const [invoiceNo, setInvoiceNo] = useState(() => Math.floor(100000 + Math.random() * 900000).toString());
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [serialNo, setSerialNo] = useState('1');

  const [currentCustomer, setCurrentCustomer] = useState<Customer | null>(null);
  const [currentOfficer, setCurrentOfficer] = useState<Officer | null>(null);

  const [items, setItems] = useState<SaleItem[]>([]);
  const [discount, setDiscount] = useState(0);
  const [paidAmount, setPaidAmount] = useState(0);

  const [priceType, setPriceType] = useState<'tp' | 'mrp' | 'sp'>('tp');
  const [productSearchCode, setProductSearchCode] = useState('');
  const [customerSearchId, setCustomerSearchId] = useState('');
  const [officerSearchId, setOfficerSearchId] = useState('');

  const [showInvoiceReport, setShowInvoiceReport] = useState<Sale | null>(null);

  const fetchCustomer = (id: string) => {
    const found = customers.find(c => c.id.toLowerCase() === id.toLowerCase());
    setCurrentCustomer(found || null);
  };

  const fetchOfficer = (id: string) => {
    const found = officers.find(o => o.id.toLowerCase() === id.toLowerCase());
    setCurrentOfficer(found || null);
  };

  const handleProductSearch = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      const found = products.find(p => p.code === productSearchCode);
      if (found) {
        if (found.stock <= 0) {
          alert(lang === 'BN' ? "স্টক শেষ!" : "Out of stock!");
          return;
        }

        let price = found.tpPrice;
        if (priceType === 'mrp') price = found.mrpPrice;
        if (priceType === 'sp') price = found.spPrice || found.tpPrice;

        const existingItem = items.find(i => i.productCode === found.code);
        if (existingItem) {
          setItems(items.map(i => i.productCode === found.code ? { ...i, quantity: i.quantity + 1, total: (i.quantity + 1) * i.unitPrice } : i));
        } else {
          setItems([...items, {
            productCode: found.code,
            productName: found.name,
            quantity: 1,
            unitPrice: price,
            total: price,
            batchNumber: ''
          }]);
        }
        setProductSearchCode('');
      } else {
        alert(lang === 'BN' ? "প্রোডাক্ট কোড পাওয়া যায়নি" : "Product Code not found");
      }
    }
  };

  const removeItem = (index: number) => setItems(items.filter((_, i) => i !== index));

  const updateItemQty = (index: number, qty: number) => {
    const newItems = [...items];
    newItems[index].quantity = qty;
    newItems[index].total = qty * newItems[index].unitPrice;
    setItems(newItems);
  };

  const updateItemBatch = (index: number, batch: string) => {
    const newItems = [...items];
    newItems[index].batchNumber = batch;
    setItems(newItems);
  };

  const totalAmount = items.reduce((sum, i) => sum + i.total, 0);
  const netAmount = totalAmount - discount;
  const dueAmount = netAmount - paidAmount;

  const handleSave = () => {
    if (!currentCustomer || !currentOfficer || items.length === 0) {
      alert(lang === 'BN' ? "কাস্টমার, অফিসার এবং কমপক্ষে একটি প্রোডাক্ট নির্বাচন করুন।" : "Please ensure Customer, Officer and at least one item are selected.");
      return;
    }

    const sale: Sale = {
      invoiceNo,
      date,
      serialNo,
      officerId: currentOfficer.id,
      customerId: currentCustomer.id,
      items,
      totalAmount,
      discount,
      netAmount,
      paidAmount,
      dueAmount,
      paymentMethod: paidAmount === 0 ? 'Credit' : (paidAmount === netAmount ? 'Cash' : 'Partial')
    };

    onAddSale(sale);
    setShowInvoiceReport(sale);

    // Reset form after saving
    setItems([]);
    setDiscount(0);
    setPaidAmount(0);
    setInvoiceNo(Math.floor(100000 + Math.random() * 900000).toString());
