    const today = new Date().toISOString().split('T')[0];
    const newSales = sales.map(s => {
      if (s.invoiceNo === invoiceNo) {
        return {
          ...s,
          paidAmount: s.netAmount,
          dueAmount: 0,
          paymentMethod: 'Cash' as any,
          paymentDate: today
        };
      }
      return s;
    });
    setSales(newSales);

    // Recalculate customer balance
    if (viewStatement) {
      const sale = sales.find(s => s.invoiceNo === invoiceNo);
      if (sale) {
        setCustomers(prev => prev.map(c => {
          if (c.id === viewStatement.id) {
            return { ...c, balance: c.balance + sale.dueAmount };
          }
          return c;
        }));
      }
    }
