                        <td className="px-4 py-4 text-right text-slate-900">
                          ৳{getCustomerSales(viewStatement.id).reduce((sum, s) => sum + s.netAmount, 0).toLocaleString()}
                        </td>
                        <td className="px-4 py-4 text-right text-emerald-600">
                          ৳{getCustomerSales(viewStatement.id).reduce((sum, s) => sum + s.paidAmount, 0).toLocaleString()}
                        </td>
                        <td className="px-4 py-4 text-right text-rose-600">
                          ৳{getCustomerSales(viewStatement.id).reduce((sum, s) => sum + s.dueAmount, 0).toLocaleString()}
                        </td>
                        <td className="no-print"></td>
                      </tr>
                    </tfoot>
                  </table>
                </div>

                <div className="flex flex-col items-end pt-10 gap-16">
                   <div className="flex justify-between w-full px-10">
                      <div className="flex flex-col items-center">
