                         <p className="text-[10px] font-black uppercase text-[#722f37] tracking-widest">Company Seal & Authorized Sign</p>
                      </div>
                   </div>
                </div>

                <div className="text-center pt-8 border-t border-slate-50">
                  <p className="text-[8px] font-black text-slate-300 uppercase tracking-[0.5em]">This is an automated system audit report from ABS FEED INDUSTRIES LIMITED</p>
                </div>
             </div>
          </div>
        </div>
      )}

      {/* Edit Customer Modal */}
      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm no-print">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden border border-white/20">
            <div className="bg-slate-900 p-8 text-white flex justify-between items-center">
              <div className="flex items-center gap-4">
                <div className="p-3 bg-emerald-600 rounded-2xl shadow-xl shadow-emerald-500/20">
                  <User size={24} />
                </div>
                <div>
                  <h2 className="text-2xl font-black tracking-tight">{editingCustomer ? (lang === 'BN' ? 'তথ্য পরিবর্তন' : 'Edit Profile') : (lang === 'BN' ? 'নতুন কাস্টমার যোগ' : 'Create Account')}</h2>
                  <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mt-1">Customer & Credit Profile</p>
                </div>
              </div>
              <button onClick={() => setShowModal(false)} className="p-3 hover:bg-slate-800 rounded-2xl transition-colors text-slate-400">
                <X size={24} />
              </button>
            </div>

            <form className="p-10 space-y-8" onSubmit={handleSubmit}>
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{lang === 'BN' ? 'আইডি' : 'Partner ID'}</label>
                  <input 
                    required 
                    type="text" 
                    value={formData.id} 
                    onChange={e => setFormData({...formData, id: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 outline-none focus:ring-2 focus:ring-rose-800 font-bold text-slate-700"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{lang === 'BN' ? 'ধরণ' : 'Type'}</label>
                  <select 
                    value={formData.type} 
                    onChange={e => setFormData({...formData, type: e.target.value as any})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 outline-none focus:ring-2 focus:ring-rose-800 font-bold text-slate-700"
                  >
                    <option value="Dealer">Dealer</option>
                    <option value="Retail">Retailer</option>
                    <option value="Customer">General Customer</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{lang === 'BN' ? 'কাস্টমার নাম' : 'Full Name'}</label>
                  <input 
                    required 
                    type="text" 
                    value={formData.name} 
                    onChange={e => setFormData({...formData, name: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 outline-none focus:ring-2 focus:ring-rose-800 font-bold text-slate-700"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{lang === 'BN' ? 'কোম্পানি নাম' : 'Company Name'}</label>
                  <input 
                    type="text" 
                    value={formData.companyName} 
                    onChange={e => setFormData({...formData, companyName: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 outline-none focus:ring-2 focus:ring-rose-800 font-bold text-slate-700"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{lang === 'BN' ? 'মোবাইল নম্বর' : 'Mobile Number'}</label>
                  <input 
                    required 
                    type="tel" 
                    value={formData.mobile} 
                    onChange={e => setFormData({...formData, mobile: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 outline-none focus:ring-2 focus:ring-rose-800 font-bold text-slate-700"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{lang === 'BN' ? 'ক্রেডিট লিমিট' : 'Credit Limit'}</label>
                  <input 
                    type="number" 
                    value={formData.creditLimit} 
                    onChange={e => setFormData({...formData, creditLimit: parseFloat(e.target.value) || 0})}
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 outline-none focus:ring-2 focus:ring-emerald-500 font-bold text-emerald-600"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{lang === 'BN' ? 'বর্তমান ব্যালেন্স/ডিউ' : 'Current Balance/Due'}</label>
                <input 
                  type="number" 
                  value={formData.balance} 
                  onChange={e => setFormData({...formData, balance: parseFloat(e.target.value) || 0})}
                  className={`w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 outline-none focus:ring-2 font-black text-lg ${formData.balance && formData.balance < 0 ? 'text-rose-600 focus:ring-rose-500' : 'text-emerald-600 focus:ring-emerald-500'}`}
                  placeholder="Negative for due, positive for credit"
                />
                <p className="text-[9px] text-slate-400 font-bold ml-1 uppercase italic tracking-tighter">* Use negative values for DUE/BALANCE (e.g. -5000)</p>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{lang === 'BN' ? 'ঠিকানা' : 'Full Address'}</label>
                <textarea 
                  rows={2}
                  value={formData.address} 
                  onChange={e => setFormData({...formData, address: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 outline-none focus:ring-2 focus:ring-rose-800 font-bold text-slate-700 resize-none"
                />
              </div>

              <div className="pt-6 border-t border-slate-100 flex gap-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 bg-slate-100 text-slate-500 font-black py-5 rounded-2xl transition-all active:scale-95 uppercase text-[10px] tracking-widest">{t('cancel')}</button>
                <button type="submit" className="flex-1 bg-emerald-600 text-white font-black py-5 rounded-2xl transition-all active:scale-95 shadow-xl shadow-emerald-500/20 uppercase text-[10px] tracking-widest">{t('save')}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CustomerList;

import React, { useState, useContext, useEffect } from 'react';
import { Customer, Sale, Officer } from '../types';
import { Search, Plus, MapPin, Phone, Building, User, X, Printer, FileText, Calendar, UserCheck, ShieldCheck, Receipt, PieChart, Activity, Mail, CheckCircle, Edit, Save } from 'lucide-react';
import { LanguageContext } from '../App';

interface CustomerListProps {
  customers: Customer[];
  setCustomers: React.Dispatch<React.SetStateAction<Customer[]>>;
}

const CustomerList: React.FC<CustomerListProps> = ({ customers, setCustomers }) => {
  const { t, lang, companyName } = useContext(LanguageContext)!;
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingCustomer, setEditingCustomer] = useState<Customer | null>(null);
  const [viewStatement, setViewStatement] = useState<Customer | null>(null);

  const [sales, setSales] = useState<Sale[]>(() => JSON.parse(localStorage.getItem('erp_sales') || '[]'));
  const officers: Officer[] = JSON.parse(localStorage.getItem('erp_officers') || '[]');

  useEffect(() => {
    localStorage.setItem('erp_sales', JSON.stringify(sales));
  }, [sales]);

  const [formData, setFormData] = useState<Partial<Customer>>({
    type: 'Dealer',
    creditLimit: 0,
    balance: 0
  });

  const handleOpenModal = (c?: Customer) => {
    if (c) {
      setEditingCustomer(c);
      setFormData(c);
    } else {
      setEditingCustomer(null);
      setFormData({
        id: `C${Math.floor(Math.random() * 1000).toString().padStart(3, '0')}`,
        name: '', companyName: '', address: '', mobile: '', type: 'Dealer', creditLimit: 500000, balance: 0
      });
    }
    setShowModal(true);
  };

  const handleUpdatePayment = (invoiceNo: string) => {
    const today = new Date().toISOString().split('T')[0];
    const newSales = sales.map(s => {
      if (s.invoiceNo === invoiceNo) {
        return {
          ...s,
          paidAmount: s.netAmount,
          dueAmount: 0,
          paymentMethod: 'Cash' as any,
          paymentDate: today
        };
      }
      return s;
    });
    setSales(newSales);

    if (viewStatement) {
      const sale = sales.find(s => s.invoiceNo === invoiceNo);
      if (sale) {
        setCustomers(prev => prev.map(c => {
          if (c.id === viewStatement.id) {
            return { ...c, balance: c.balance + sale.dueAmount };
          }
          return c;
        }));
      }
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.id) return;

    if (editingCustomer) {
      setCustomers(prev => prev.map(c => c.id === editingCustomer.id ? { ...c, ...formData as Customer } : c));
    } else {
      setCustomers(prev => [...prev, formData as Customer]);
    }
    setShowModal(false);
  };

  const filtered = customers.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.companyName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getCustomerSales = (customerId: string) => {
    return sales.filter(s => s.customerId === customerId).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 no-print">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">{lang === 'BN' ? 'কাস্টমার ও ডিলার' : 'Customer Network'}</h1>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Partnership & Credit Management</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="bg-[#722f37] text-white px-8 py-4 rounded-2xl font-black flex items-center justify-center gap-3 shadow-xl shadow-rose-900/20 hover:bg-rose-950 transition-all active:scale-95 text-sm uppercase tracking-widest"
        >
          <Plus size={20} /> {lang === 'BN' ? 'নতুন কাস্টমার' : 'Add Partner'}
        </button>
      </div>

      <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-200 no-print">
        <div className="relative">
          <input 
            type="text" 
            placeholder={lang === 'BN' ? "আইডি, নাম বা কোম্পানি দিয়ে খুজুন..." : "Search by ID, name or company..."} 
            className="w-full pl-14 pr-4 py-4 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-rose-800 bg-slate-50/50 font-bold text-slate-700 transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <Search className="absolute left-5 top-4.5 text-slate-300" size={24} />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 no-print">
        {filtered.map((customer) => (
          <div key={customer.id} className="bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden hover:shadow-2xl hover:border-rose-100 transition-all duration-300 group">
            <div className="p-8 border-b border-slate-50 flex justify-between items-start">
              <div>
                <span className="text-[10px] font-black text-[#722f37] bg-rose-50 px-2 py-1 rounded-lg uppercase tracking-widest">{customer.id}</span>
                <h3 className="text-xl font-black text-slate-900 mt-3 group-hover:text-[#722f37] transition-colors">{customer.name}</h3>
                <div className="flex items-center gap-1.5 text-[10px] text-slate-400 font-black uppercase mt-1 tracking-wider">
                  <Building size={14} className="text-slate-300" /> {customer.companyName}
                </div>
              </div>
              <span className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest ${customer.type === 'Dealer' ? 'bg-purple-100 text-purple-700' : 'bg-rose-100 text-[#722f37]'}`}>
                {customer.type}
              </span>
            </div>

            <div className="p-8 space-y-4 bg-slate-50/30">
              <div className="flex items-start gap-4 text-xs text-slate-600 font-bold leading-relaxed">
                <MapPin size={18} className="text-slate-300 shrink-0" />
                <span className="line-clamp-2">{customer.address}</span>
              </div>
              <div className="flex items-center gap-4 text-xs text-slate-600 font-black">
                <Phone size={18} className="text-slate-300 shrink-0" />
                <span>{customer.mobile}</span>
              </div>

              <div className="mt-8 pt-8 border-t border-slate-100 grid grid-cols-2 gap-4">
                <div className="p-4 bg-white rounded-3xl border border-slate-100 shadow-sm">
                  <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest">{lang === 'BN' ? 'ক্রেডিট লিমিট' : 'Limit'}</p>
                  <p className="text-sm font-black text-slate-800 mt-1">৳{customer.creditLimit.toLocaleString()}</p>
                </div>
                <div className="p-4 bg-white rounded-3xl border border-slate-100 shadow-sm text-right">
                  <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest">{lang === 'BN' ? 'বর্তমান ব্যালেন্স' : 'Balance'}</p>
                  <p className={`text-sm font-black mt-1 ${customer.balance < 0 ? 'text-rose-600' : 'text-emerald-600'}`}>
                    ৳{Math.abs(customer.balance).toLocaleString()} {customer.balance < 0 ? 'DUE' : 'CR'}
                  </p>
                </div>
              </div>
            </div>

            <div className="p-4 bg-white flex gap-3">
              <button onClick={() => handleOpenModal(customer)} className="flex-1 text-[10px] font-black uppercase tracking-widest py-3.5 bg-slate-100 text-slate-600 rounded-2xl hover:bg-slate-200 transition-all transform active:scale-95">{t('edit')}</button>
              <button onClick={() => setViewStatement(customer)} className="flex-1 text-[10px] font-black uppercase tracking-widest py-3.5 bg-slate-900 text-white rounded-2xl hover:bg-[#722f37] transition-all transform active:scale-95 shadow-lg shadow-slate-200 flex items-center justify-center gap-2">
                <Activity size={14} /> {lang === 'BN' ? 'স্টেটমেন্ট' : 'Statement'}
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Account Statement Modal */}
      {viewStatement && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-sm no-print">
          <div className="bg-white w-full max-w-6xl rounded-[3rem] shadow-2xl overflow-hidden print-m-0 modal-container">
             <div className="bg-[#722f37] p-8 text-white flex justify-between items-center no-print">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-white/10 rounded-2xl">
                    <FileText size={24} />
                  </div>
                  <div>
                    <h2 className="text-xl font-black tracking-tight">{lang === 'BN' ? 'অ্যাকাউন্ট স্টেটমেন্ট' : 'Account Statement'}</h2>
                    <p className="text-rose-200 text-[10px] font-bold uppercase tracking-widest">Dealer Ledger Detail</p>
                  </div>
