export class DatabaseService {
  private static async request(collection: string, action: string, body: any = {}) {
    // In a real-world scenario, you would call your backend API here.
    // For this implementation, we simulate the async behavior and use LocalStorage as a local cache
    // but the structure is ready for direct API integration.

    const key = `mongodb_sync_${collection}`;
    const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

    try {
      await delay(300); // Simulate network latency

      // If we were using actual MongoDB Data API, the call would look like:
      /*
      const response = await fetch(`${API_BASE_URL}/${action}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Access-Control-Request-Headers': '*' },
        body: JSON.stringify({ ...DB_CONFIG, collection, ...body })
      });
      return await response.json();
      */

      // Fallback/Simulated Persistence logic
      if (action === 'find') {
        const data = localStorage.getItem(key);
        return data ? JSON.parse(data) : [];
      }

      if (action === 'saveAll') {
        localStorage.setItem(key, JSON.stringify(body.documents));
        return { matchedCount: body.documents.length };
      }

      if (action === 'insertOne') {
        const existing = JSON.parse(localStorage.getItem(key) || '[]');
        existing.push(body.document);
        localStorage.setItem(key, JSON.stringify(existing));
        return { insertedId: 'simulated_id' };
      }

      if (action === 'deleteOne') {
        const existing = JSON.parse(localStorage.getItem(key) || '[]');
        const filtered = existing.filter((item: any) => item.invoiceNo !== body.filter.invoiceNo && item.id !== body.filter.id);
        localStorage.setItem(key, JSON.stringify(filtered));
        return { deletedCount: 1 };
      }

    } catch (error) {
      console.error(`Database Error [${collection}]:`, error);
      throw error;
    }
  }

  static async getProducts() { return await this.request('products', 'find'); }
  static async saveProducts(products: any[]) { return await this.request('products', 'saveAll', { documents: products }); }

  static async getCustomers() { return await this.request('customers', 'find'); }
  static async saveCustomers(customers: any[]) { return await this.request('customers', 'saveAll', { documents: customers }); }

  static async getOfficers() { return await this.request('officers', 'find'); }
  static async saveOfficers(officers: any[]) { return await this.request('officers', 'saveAll', { documents: officers }); }

  static async getSales() { return await this.request('sales', 'find'); }
  static async addSale(sale: any) { return await this.request('sales', 'insertOne', { document: sale }); }
  static async deleteSale(invoiceNo: string) { return await this.request('sales', 'deleteOne', { filter: { invoiceNo } }); }
}

