  const [lang, setLang] = useState<Lang>(() => (localStorage.getItem('erp_lang') as Lang) || 'BN');
  const [isDbLoading, setIsDbLoading] = useState(true);

  const t = (key: string) => translations[lang][key] || key;
  const companyName = t('companyLabel');

  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [officers, setOfficers] = useState<Officer[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);

  // Initial Database Load
  useEffect(() => {
    const initDb = async () => {
      try {
        const [p, c, o, s] = await Promise.all([
          DatabaseService.getProducts(),
          DatabaseService.getCustomers(),
          DatabaseService.getOfficers(),
          DatabaseService.getSales()
        ]);

        setProducts(p.length > 0 ? p : INITIAL_PRODUCTS);
        setCustomers(c.length > 0 ? c : INITIAL_CUSTOMERS);
        setOfficers(o.length > 0 ? o : INITIAL_OFFICERS);
        setSales(s);
      } catch (err) {
        console.error("Initial load failed", err);
      } finally {
        setIsDbLoading(false);
      }
    };
    initDb();
  }, []);

  // Effect to sync changes back to MongoDB
  useEffect(() => {
    if (!isDbLoading) {
      DatabaseService.saveProducts(products);
      DatabaseService.saveCustomers(customers);
      DatabaseService.saveOfficers(officers);
    }
  }, [products, customers, officers, isDbLoading]);

  const handleLogin = () => {
    setIsLoggedIn(true);
    localStorage.setItem('erp_logged_in', 'true');
  };

  const addSale = async (newSale: Sale) => {
    // 1. Update State Locally for Instant Feedback
    setSales(prev => [...prev, newSale]);
    setProducts(prev => prev.map(p => {
      const soldItem = newSale.items.find(si => si.productCode === p.code);
      if (soldItem) return { ...p, stock: p.stock - soldItem.quantity };
      return p;
    }));
    if (newSale.dueAmount > 0) {
      setCustomers(prev => prev.map(c => {
        if (c.id === newSale.customerId) return { ...c, balance: c.balance - newSale.dueAmount };
        return c;
      }));
    }

    // 2. Sync with MongoDB
    try {
      await DatabaseService.addSale(newSale);
    } catch (err) {
      alert("Failed to sync sale to database. It is saved locally.");
    }
  };

  const deleteSale = async (invoiceNo: string) => {
    const saleToDelete = sales.find(s => s.invoiceNo === invoiceNo);
    if (!saleToDelete) return;

    if (!confirm(lang === 'BN' ? 'আপনি কি নিশ্চিতভাবে এই ইনভয়েসটি মুছে ফেলতে চান?' : 'Are you sure you want to delete this invoice?')) return;

    // 1. Restore product stock locally
    setProducts(prev => prev.map(p => {
      const item = saleToDelete.items.find(si => si.productCode === p.code);
      if (item) return { ...p, stock: p.stock + item.quantity };
      return p;
    }));

    // 2. Restore customer balance locally
    if (saleToDelete.dueAmount > 0) {
      setCustomers(prev => prev.map(c => {
        if (c.id === saleToDelete.customerId) return { ...c, balance: c.balance + saleToDelete.dueAmount };
        return c;
      }));
    }

    // 3. Remove the sale from list locally
    setSales(prev => prev.filter(s => s.invoiceNo !== invoiceNo));

    // 4. Sync Delete with MongoDB
    try {
      await DatabaseService.deleteSale(invoiceNo);
    } catch (err) {
      alert("Failed to sync deletion with database.");
    }
  };

  if (!isLoggedIn) {
    return (
      <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
        <LoginPage onLogin={handleLogin} />
      </LanguageContext.Provider>
    );
