      try {
        // First check if server is reachable
        const connected = await DatabaseService.checkConnection();
        setIsOnline(connected);

        const [p, c, o, s] = await Promise.all([
          DatabaseService.getProducts(),
          DatabaseService.getCustomers(),
          DatabaseService.getOfficers(),
          DatabaseService.getSales()
        ]);

        setProducts(p.length > 0 ? p : INITIAL_PRODUCTS);
        setCustomers(c.length > 0 ? c : INITIAL_CUSTOMERS);
        setOfficers(o.length > 0 ? o : INITIAL_OFFICERS);
        setSales(s || []);
      } catch (err) {
        console.warn("Initial load fallbacked to local data", err);
        setIsOnline(false);
      } finally {
        setIsDbLoading(false);
      }
    };
    initDb();
  }, []);

  // Sync Logic: Pushing changes to Express server
  useEffect(() => {
    const syncWithDb = async () => {
      if (!isDbLoading && isOnline) {
        setIsSyncing(true);
        try {
          await Promise.all([
            DatabaseService.saveProducts(products),
            DatabaseService.saveCustomers(customers),
            DatabaseService.saveOfficers(officers)
          ]);
        } catch (err) {
          console.error("Sync failed", err);
        } finally {
          setIsSyncing(false);
        }
      }
    };

    const timeout = setTimeout(syncWithDb, 2000); 
    return () => clearTimeout(timeout);
  }, [products, customers, officers, isDbLoading, isOnline]);

  const handleLogin = () => {
    setIsLoggedIn(true);
    localStorage.setItem('erp_logged_in', 'true');
  };

  const addSale = async (newSale: Sale) => {
    setSales(prev => [...prev, newSale]);
    setProducts(prev => prev.map(p => {
      const soldItem = newSale.items.find(si => si.productCode === p.code);
      if (soldItem) return { ...p, stock: p.stock - soldItem.quantity };
      return p;
    }));
    if (newSale.dueAmount > 0) {
      setCustomers(prev => prev.map(c => {
        if (c.id === newSale.customerId) return { ...c, balance: c.balance - newSale.dueAmount };
        return c;
      }));
    }

    if (isOnline) {
      setIsSyncing(true);
      try {
        await DatabaseService.addSale(newSale);
      } catch (err) {
        console.error("Failed to add sale via Express", err);
      } finally {
        setIsSyncing(false);
      }
    }
  };

  const deleteSale = async (invoiceNo: string) => {
    const saleToDelete = sales.find(s => s.invoiceNo === invoiceNo);
    if (!saleToDelete) return;

    if (!confirm(lang === 'BN' ? 'আপনি কি নিশ্চিতভাবে এই ইনভয়েসটি মুছে ফেলতে চান?' : 'Are you sure you want to delete this invoice?')) return;

    setProducts(prev => prev.map(p => {
      const item = saleToDelete.items.find(si => si.productCode === p.code);
      if (item) return { ...p, stock: p.stock + item.quantity };
      return p;
    }));
    if (saleToDelete.dueAmount > 0) {
      setCustomers(prev => prev.map(c => {
        if (c.id === saleToDelete.customerId) return { ...c, balance: c.balance + saleToDelete.dueAmount };
        return c;
      }));
    }
    setSales(prev => prev.filter(s => s.invoiceNo !== invoiceNo));

    if (isOnline) {
      setIsSyncing(true);
      try {
        await DatabaseService.deleteSale(invoiceNo);
      } catch (err) {
        console.error("Failed to delete sale via Express", err);
      } finally {
        setIsSyncing(false);
      }
    }
  };

  const runSmartAnalysis = async () => {
    setIsAnalyzing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `
        As a business analyst for ABS FEED INDUSTRIES LIMITED, analyze this product data:
        ${JSON.stringify(products.map(p => ({ 
          name: p.name, 
          cat: p.category, 
          stock: p.stock, 
          cost: p.purchasePrice, 
          tp: p.tpPrice,
          bag: p.bagSize
        })))}

        Provide a detailed analysis in ${lang === 'BN' ? 'Bengali' : 'English'}.
        Include:
        1. Top 3 most profitable products based on margin.
        2. Critical stock warnings.
        3. Strategic recommendations for sales officers.
        Use a professional and motivational tone. Format with bold headers and bullet points.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });

      setAiAnalysis(response.text || "Could not generate analysis.");
    } catch (err) {
      console.error("AI Analysis failed", err);
      setAiAnalysis(lang === 'BN' ? "বিশ্লেষণ করতে ত্রুটি হয়েছে। অনুগ্রহ করে পরে চেষ্টা করুন।" : "AI Analysis encountered an error. Please try again later.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  if (!isLoggedIn) {
    return (
      <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
        <LoginPage onLogin={handleLogin} />
      </LanguageContext.Provider>
    );
  }

  if (isDbLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-900 text-white font-black overflow-hidden">
        <div className="flex flex-col items-center gap-8 animate-in fade-in zoom-in duration-500">
          <div className="relative">
             <div className="absolute inset-0 bg-[#722f37] blur-3xl opacity-30 animate-pulse"></div>
             <Loader2 className="animate-spin text-[#722f37] relative" size={80} />
          </div>
          <div className="text-center space-y-2">
            <h2 className="text-2xl tracking-[0.2em] uppercase font-black">ABS FEED ERP</h2>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Synchronizing System Data...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
      <HashRouter>
        <div className="flex min-h-screen bg-slate-50">
          <Sidebar isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} />

          <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
            <header className="h-20 flex items-center justify-between px-8 bg-white border-b border-slate-200 no-print">
              <div className="flex items-center gap-4">
                <button className="md:hidden p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors" onClick={() => setSidebarOpen(true)}>
                  <Menu size={24} />
                </button>
                <div className="hidden md:block">
                  <div className="flex items-center gap-3">
                    <h2 className="text-xl font-black text-[#722f37] tracking-tight">{companyName}</h2>
                    <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full border shadow-sm ${isOnline ? 'bg-slate-900 border-slate-800' : 'bg-rose-50 border-rose-100'}`}>
                      <div className="relative flex h-2 w-2">
                        {isOnline && <span className={`animate-ping absolute inline-flex h-full w-full rounded-full ${isSyncing ? 'bg-amber-400' : 'bg-emerald-400'} opacity-75`}></span>}
                        <span className={`relative inline-flex rounded-full h-2 w-2 ${isOnline ? (isSyncing ? 'bg-amber-500' : 'bg-emerald-500') : 'bg-rose-500'}`}></span>
                      </div>
                      <span className={`text-[8px] font-black uppercase tracking-widest flex items-center gap-1 ${isOnline ? 'text-white' : 'text-rose-600'}`}>
                        {isOnline ? (isSyncing ? <CloudUpload size={10} className="text-amber-400" /> : <Wifi size={10} className="text-emerald-400" />) : <WifiOff size={10} />}
                        {isOnline ? (isSyncing ? 'Syncing...' : 'Live Server') : 'Offline Mode'}
                      </span>
                    </div>
                  </div>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em] mt-0.5">{t('admin')}</p>
                </div>
              </div>

              <div className="flex items-center gap-6">
                <button 
                  onClick={runSmartAnalysis}
                  disabled={isAnalyzing}
                  className="hidden lg:flex items-center gap-2 bg-slate-900 text-emerald-400 border border-slate-800 px-5 py-2.5 rounded-2xl text-xs font-black transition-all hover:bg-black shadow-lg active:scale-95"
                >
                  {isAnalyzing ? <Loader2 size={18} className="animate-spin" /> : <BrainCircuit size={18} />}
                  <span>{t('smartAnalysis')}</span>
                </button>

                <button 
                  onClick={() => setLang(lang === 'EN' ? 'BN' : 'EN')}
                  className="flex items-center gap-2 bg-[#722f37] text-white px-5 py-2.5 rounded-2xl text-xs font-black transition-all hover:bg-[#5a252c] shadow-lg shadow-rose-900/20 active:scale-95"
                >
                  <Languages size={18} />
                  <span>{t('toggleLang')}</span>
                </button>

                <div className="flex items-center gap-4 pl-6 border-l border-slate-200">
                  <div className="text-right hidden sm:block">
                    <p className="text-sm font-black text-slate-900 leading-none mb-1">Administrator</p>
                    <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-wider flex items-center justify-end gap-1">
                      <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span> Online
                    </p>
                  </div>
                  <div className="w-12 h-12 rounded-2xl bg-rose-50 flex items-center justify-center text-[#722f37] font-black border-2 border-white shadow-inner">
                    AD
                  </div>
                </div>
              </div>
            </header>

            <main className="flex-1 overflow-y-auto p-6 md:p-10">
              <Routes>
                <Route path="/" element={<Dashboard products={products} sales={sales} customers={customers} onDeleteSale={deleteSale} />} />
                <Route path="/sales" element={<SalesEntry products={products} customers={customers} officers={officers} onAddSale={addSale} />} />
                <Route path="/products" element={<ProductList products={products} setProducts={setProducts} onAnalyze={runSmartAnalysis} />} />
                <Route path="/stock" element={<StockManagement products={products} setProducts={setProducts} />} />
                <Route path="/customers" element={<CustomerList customers={customers} setCustomers={setCustomers} />} />
                <Route path="/officers" element={<OfficerList officers={officers} setOfficers={setOfficers} />} />
                <Route path="/reports" element={<Reports sales={sales} products={products} officers={officers} customers={customers} onDeleteSale={deleteSale} />} />
                <Route path="*" element={<Navigate to="/" />} />
              </Routes>
            </main>
          </div>
        </div>

        {/* AI Analysis Modal */}
        {(isAnalyzing || aiAnalysis) && (
          <div className="fixed inset-0 z-[300] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md">
            <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden border border-white/20 flex flex-col h-[80vh]">
              <div className="bg-slate-900 p-8 text-white flex justify-between items-center shrink-0">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-emerald-600 rounded-2xl shadow-xl shadow-emerald-500/20">
                    <Sparkles size={24} className="animate-pulse" />
                  </div>
                  <div>
                    <h2 className="text-2xl font-black tracking-tight">{t('analysisDone')}</h2>
                    <p className="text-emerald-400 text-[10px] font-black uppercase tracking-widest mt-1">Powered by Google Gemini 3</p>
                  </div>
                </div>
                <button onClick={() => setAiAnalysis(null)} className="p-3 hover:bg-slate-800 rounded-2xl transition-colors text-slate-400">
                  <X size={24} />
                </button>
              </div>

              <div className="flex-1 overflow-y-auto p-10 bg-slate-50">
                {isAnalyzing ? (
                  <div className="h-full flex flex-col items-center justify-center space-y-6 text-center">
                    <div className="relative">
                      <Zap className="text-emerald-500 animate-bounce" size={60} />
                      <div className="absolute inset-0 bg-emerald-400 blur-3xl opacity-20"></div>
                    </div>
                    <p className="text-xl font-black text-slate-900 tracking-tight">{t('analysisWait')}</p>
                    <div className="flex gap-2">
                      <span className="w-2 h-2 bg-emerald-500 rounded-full animate-bounce"></span>
                      <span className="w-2 h-2 bg-emerald-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                      <span className="w-2 h-2 bg-emerald-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                    </div>
                  </div>
                ) : (
                  <div className="prose prose-slate max-w-none">
                    <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm leading-relaxed whitespace-pre-wrap text-slate-700 font-medium">
                      {aiAnalysis}
                    </div>
                    <div className="mt-8 flex justify-center">
                       <button onClick={() => setAiAnalysis(null)} className="px-10 py-4 bg-slate-900 text-white font-black rounded-2xl text-xs uppercase tracking-widest shadow-xl hover:bg-black transition-all">Close Report</button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </HashRouter>
    </LanguageContext.Provider>
  );
}

import React, { useState, useContext } from 'react';
import { Product } from '../types';
import { Search, Filter, Plus, Edit2, Trash2, X, Package, Tag, TrendingUp, DollarSign, BarChart2, BrainCircuit } from 'lucide-react';
import { LanguageContext } from '../App';

interface ProductListProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  onAnalyze?: () => void;
}

const ProductList: React.FC<ProductListProps> = ({ products, setProducts, onAnalyze }) => {
  const { t, lang } = useContext(LanguageContext)!;
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState('All');
  const [showModal, setShowModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  const [formData, setFormData] = useState<Partial<Product>>({
    status: 'Active',
    unit: 'Bag',
    stock: 0,
    mrpPrice: 0,
    tpPrice: 0,
    spPrice: 0,
    purchasePrice: 0
  });

  const categories = ['All', 'Poultry Feed', 'Fish Feed', 'Cattle Feed'];

  const handleOpenModal = (p?: Product) => {
    if (p) {
      setEditingProduct(p);
      setFormData(p);
    } else {
      setEditingProduct(null);
      setFormData({
        code: '', name: '', category: 'Poultry Feed', unit: 'Bag', bagSize: '50 kg',
        purchasePrice: 0, tpPrice: 0, mrpPrice: 0, spPrice: 0, stock: 0, status: 'Active'
      });
    }
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.code || !formData.name) return;

    if (editingProduct) {
      setProducts(prev => prev.map(p => p.code === editingProduct.code ? { ...p, ...formData as Product } : p));
    } else {
      if (products.some(p => p.code === formData.code)) {
        alert(lang === 'BN' ? "এই কোডটি ইতিমধ্যে ব্যবহৃত হয়েছে" : "Code already exists");
        return;
      }
      setProducts(prev => [...prev, formData as Product]);
    }
    setShowModal(false);
  };

  const filtered = products.filter(p => {
    const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.code.includes(searchTerm);
    const matchesCategory = filterCategory === 'All' || p.category === filterCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">{lang === 'BN' ? 'পণ্য ও ইনভেন্টরি' : 'Inventory & Pricing'}</h1>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Grains, Feed & Stock Analysis</p>
        </div>
        <div className="flex gap-4">
          <button 
            onClick={onAnalyze}
            className="bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black flex items-center justify-center gap-3 shadow-xl shadow-emerald-900/20 hover:bg-emerald-700 transition-all active:scale-95 text-sm uppercase tracking-widest"
          >
            <BrainCircuit size={20} /> {t('smartAnalysis')}
          </button>
          <button 
            onClick={() => handleOpenModal()}
            className="bg-[#722f37] text-white px-8 py-4 rounded-2xl font-black flex items-center justify-center gap-3 shadow-xl shadow-rose-900/20 hover:bg-[#5a252c] transition-all active:scale-95 text-sm uppercase tracking-widest"
          >
            <Plus size={20} /> {lang === 'BN' ? 'নতুন পণ্য' : 'Add Product'}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 no-print">
        <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm col-span-2">
           <div className="relative">
             <input 
               type="text" 
               placeholder={lang === 'BN' ? "কোড বা নাম দিয়ে খুজুন..." : "Search by code or name..."} 
               className="w-full pl-12 pr-4 py-3 border-none rounded-xl outline-none bg-slate-50 font-bold text-slate-700"
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
             />
             <Search className="absolute left-4 top-3.5 text-slate-300" size={20} />
           </div>
        </div>
        <select 
          className="w-full border border-slate-100 rounded-3xl px-6 py-4 bg-white font-black text-slate-600 outline-none uppercase text-[10px] tracking-widest shadow-sm"
          value={filterCategory}
          onChange={(e) => setFilterCategory(e.target.value)}
        >
          {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
        </select>
        <div className="bg-[#722f37] p-5 rounded-3xl text-white flex items-center justify-between shadow-xl">
           <div>
              <p className="text-[8px] font-black uppercase opacity-60 tracking-widest">Total Inventory Value</p>
              <p className="text-lg font-black leading-none">৳{products.reduce((s,p)=>s+(p.stock*p.purchasePrice), 0).toLocaleString()}</p>
           </div>
           <DollarSign size={20} className="text-rose-300 opacity-40" />
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-6 py-6 text-[9px] font-black text-slate-400 uppercase tracking-widest">Code</th>
                <th className="px-6 py-6 text-[9px] font-black text-slate-400 uppercase tracking-widest">Product Details</th>
                <th className="px-6 py-6 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Cost</th>
                <th className="px-6 py-6 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Trade (TP)</th>
                <th className="px-6 py-6 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Profit Margin</th>
                <th className="px-6 py-6 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Stock</th>
                <th className="px-6 py-6 text-[9px] font-black text-slate-400 uppercase tracking-widest text-right">Total Value</th>
                <th className="px-6 py-6 text-[9px] font-black text-slate-400 uppercase tracking-widest text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filtered.map((product) => {
                const margin = product.purchasePrice > 0 ? ((product.tpPrice - product.purchasePrice) / product.purchasePrice * 100).toFixed(1) : '0';
                return (
                  <tr key={product.code} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-6">
                      <span className="font-black text-[#722f37] bg-rose-50 px-2 py-1 rounded text-[10px] border border-rose-100">{product.code}</span>
                    </td>
                    <td className="px-6 py-6">
                      <div className="text-xs font-black text-slate-900 uppercase">{product.name}</div>
                      <div className="flex items-center gap-2 mt-1 opacity-60">
                        <Tag size={10} className="text-slate-400" />
                        <span className="text-[8px] font-black text-slate-500 uppercase">{product.category} • {product.bagSize}</span>
                      </div>
                    </td>
                    <td className="px-6 py-6 text-[11px] font-bold text-slate-400 text-right">৳{product.purchasePrice.toLocaleString()}</td>
                    <td className="px-6 py-6 text-[11px] font-black text-slate-900 text-right">৳{product.tpPrice.toLocaleString()}</td>
                    <td className="px-6 py-6 text-right">
                      <div className="inline-flex items-center gap-1 text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full">
                        <TrendingUp size={10} /> {margin}%
                      </div>
                    </td>
                    <td className="px-6 py-6 text-center">
                      <div className={`text-[11px] font-black ${product.stock < 20 ? 'text-rose-600 bg-rose-50' : 'text-slate-900 bg-slate-50'} inline-block px-2 py-1 rounded-lg border border-slate-200/50 min-w-[50px]`}>
                        {product.stock} Bag
                      </div>
                    </td>
                    <td className="px-6 py-6 text-[11px] font-black text-[#722f37] text-right">
                       ৳{(product.stock * product.purchasePrice).toLocaleString()}
                    </td>
                    <td className="px-6 py-6">
                      <div className="flex justify-center gap-2">
                        <button onClick={() => handleOpenModal(product)} className="p-2 text-slate-400 hover:text-[#722f37] transition-all"><Edit2 size={16} /></button>
                        <button className="p-2 text-slate-400 hover:text-rose-600 transition-all"><Trash2 size={16} /></button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden border border-white/20">
            <div className="bg-slate-900 p-8 text-white flex justify-between items-center">
              <div className="flex items-center gap-4">
                <div className="p-3 bg-[#722f37] rounded-2xl shadow-xl">
                  <Package size={24} />
                </div>
                <div>
                  <h2 className="text-2xl font-black tracking-tight">{editingProduct ? (lang === 'BN' ? 'পণ্য সংশোধন' : 'Edit Product') : (lang === 'BN' ? 'নতুন পণ্য যোগ' : 'Add New Product')}</h2>
                  <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mt-1">Configure item specifications</p>
                </div>
              </div>
              <button onClick={() => setShowModal(false)} className="p-3 hover:bg-slate-800 rounded-2xl transition-colors text-slate-400">
                <X size={24} />
              </button>
            </div>

            <form className="p-10 space-y-8" onSubmit={handleSubmit}>
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{lang === 'BN' ? 'পণ্য কোড' : 'Product Code'}</label>
                  <input required type="text" value={formData.code} onChange={e => setFormData({...formData, code: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 outline-none focus:ring-2 focus:ring-rose-800 font-bold text-slate-700" />
                </div>
