export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [view, setView] = useState<View>('dashboard');
  const [lang, setLang] = useState<Lang>('BN');
  const [isDbLoading, setIsDbLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isOnline, setIsOnline] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [officers, setOfficers] = useState<Officer[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);

  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);

  const t = (key: string) => translations[lang][key] || key;
  const companyName = t('companyLabel');

  const initDb = async () => {
    setIsDbLoading(true);
    try {
      const connected = await DatabaseService.checkConnection();
      setIsOnline(connected);

      const [p, c, o, s] = await Promise.all([
        DatabaseService.getProducts(),
        DatabaseService.getCustomers(),
        DatabaseService.getOfficers(),
        DatabaseService.getSales()
      ]);

      setProducts(p && p.length > 0 ? p : INITIAL_PRODUCTS);
      setCustomers(c && c.length > 0 ? c : INITIAL_CUSTOMERS);
      setOfficers(o && o.length > 0 ? o : INITIAL_OFFICERS);
      setSales(s || []);
    } catch (err) {
      console.warn("API load failed, using local storage", err);
      setIsOnline(false);
    } finally {
      setIsDbLoading(false);
    }
  };

  useEffect(() => {
    const logged = localStorage.getItem('erp_logged_in') === 'true';
    setIsLoggedIn(logged);
    const l = localStorage.getItem('erp_lang') as Lang;
    if(l) setLang(l);
    initDb();
  }, []);

  useEffect(() => {
    const syncWithDb = async () => {
      if (!isDbLoading && isOnline) {
        setIsSyncing(true);
        try {
          await Promise.all([
            DatabaseService.saveProducts(products),
            DatabaseService.saveCustomers(customers),
            DatabaseService.saveOfficers(officers)
          ]);
        } catch (err) {
          setIsOnline(false);
        } finally {
          setIsSyncing(false);
        }
      }
    };
    const timeout = setTimeout(syncWithDb, 5000); 
    return () => clearTimeout(timeout);
  }, [products, customers, officers, isDbLoading, isOnline]);

  const addSale = async (newSale: Sale) => {
    setSales(prev => [...prev, newSale]);
    setProducts(prev => prev.map(p => {
      const soldItem = newSale.items.find(si => si.productCode === p.code);
      if (soldItem) return { ...p, stock: p.stock - soldItem.quantity };
      return p;
    }));
    if (newSale.dueAmount !== 0) {
      setCustomers(prev => prev.map(c => {
        if (c.id === newSale.customerId) return { ...c, balance: c.balance - newSale.dueAmount };
        return c;
      }));
    }

    if (isOnline) {
      try {
        await DatabaseService.addSale(newSale);
      } catch (err) { console.error(err); }
    }
  };

  const deleteSale = async (invoiceNo: string) => {
    const saleToDelete = sales.find(s => s.invoiceNo === invoiceNo);
    if (!saleToDelete) return;
    if (!confirm('Confirm deletion?')) return;

    setSales(prev => prev.filter(s => s.invoiceNo !== invoiceNo));
    if (isOnline) {
      try {
        await DatabaseService.deleteSale(invoiceNo);
        initDb(); // Refresh from server to ensure sync
      } catch (err) { console.error(err); }
    }
  };

  const runSmartAnalysis = async () => {
    setIsAnalyzing(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Analyze this product data for ${companyName}: ${JSON.stringify(products)}. Generate a strategic report in ${lang}.`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      setAiAnalysis(response.text || "No response.");
    } catch (err) {
      setAiAnalysis("Analysis failed.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  if (!isLoggedIn) {
    return (
      <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
        <LoginPage onLogin={() => { setIsLoggedIn(true); localStorage.setItem('erp_logged_in', 'true'); }} />
      </LanguageContext.Provider>
    );
  }

  if (isDbLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white gap-6">
        <Loader2 className="animate-spin text-[#722f37]" size={64} />
        <h2 className="text-xl font-black tracking-widest">CONNECTING TO MONGODB...</h2>
      </div>
    );
  }

  return (
    <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
      <div className="flex min-h-screen bg-slate-50">
        <Sidebar currentView={view} setView={setView} isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} />

        <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
          <header className="h-20 flex items-center justify-between px-8 bg-white border-b border-slate-200 no-print">
            <div className="flex items-center gap-4">
              <button className="md:hidden p-2" onClick={() => setSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden md:block">
                <h2 className="text-xl font-black text-[#722f37]">{companyName}</h2>
                <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full border text-[8px] font-black uppercase ${isOnline ? 'bg-slate-900 text-white' : 'bg-rose-50 text-rose-600'}`}>
                  {isOnline ? (isSyncing ? 'Syncing...' : 'Connected to MongoDB Atlas') : 'Local Mode'}
                  {isOnline && <RefreshCw size={10} className={isSyncing ? 'animate-spin' : ''} />}
                </div>
              </div>
            </div>

            <div className="flex gap-4">
              <button onClick={runSmartAnalysis} className="bg-slate-900 text-emerald-400 px-5 py-2.5 rounded-2xl text-xs font-black flex items-center gap-2"><BrainCircuit size={18} /> AI Analysis</button>
              <button onClick={() => { setLang(lang === 'EN' ? 'BN' : 'EN'); localStorage.setItem('erp_lang', lang === 'EN' ? 'BN' : 'EN'); }} className="bg-[#722f37] text-white px-5 py-2.5 rounded-2xl text-xs font-black flex items-center gap-2"><Languages size={18} /> {t('toggleLang')}</button>
            </div>
          </header>

          <main className="flex-1 overflow-y-auto p-6 md:p-10">
            {view === 'dashboard' && <Dashboard products={products} sales={sales} customers={customers} onDeleteSale={deleteSale} />}
            {view === 'sales' && <SalesEntry products={products} customers={customers} officers={officers} onAddSale={addSale} />}
            {view === 'products' && <ProductList products={products} setProducts={setProducts} onAnalyze={runSmartAnalysis} />}
            {view === 'stock' && <StockManagement products={products} setProducts={setProducts} />}
            {view === 'customers' && <CustomerList customers={customers} setCustomers={setCustomers} />}
            {view === 'officers' && <OfficerList officers={officers} setOfficers={setOfficers} />}
            {view === 'reports' && <Reports sales={sales} products={products} officers={officers} customers={customers} onDeleteSale={deleteSale} />}
          </main>
        </div>
      </div>

      {(isAnalyzing || aiAnalysis) && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl flex flex-col h-[80vh]">
            <div className="bg-slate-900 p-8 text-white flex justify-between items-center">
              <h2 className="text-2xl font-black">{t('analysisDone')}</h2>
              <button onClick={() => setAiAnalysis(null)} className="p-2"><X size={24} /></button>
            </div>
            <div className="flex-1 overflow-y-auto p-10 bg-slate-50">
              {isAnalyzing ? <div className="h-full flex items-center justify-center"><Loader2 className="animate-spin text-emerald-500" size={48} /></div> : <div className="whitespace-pre-wrap leading-relaxed">{aiAnalysis}</div>}
            </div>
          </div>
        </div>
      )}
    </LanguageContext.Provider>
  );
}

