export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [view, setView] = useState<View>('dashboard');
  const [lang, setLang] = useState<Lang>('BN');
  const [isDbLoading, setIsDbLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isOnline, setIsOnline] = useState(false);

  const [syncLogs, setSyncLogs] = useState<SyncLogEntry[]>([]);
  const [showSyncLog, setShowSyncLog] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [officers, setOfficers] = useState<Officer[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);

  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);

  const t = (key: string) => translations[lang][key] || key;
  const companyName = t('companyLabel');

  const addLog = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
    setSyncLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 50));
  };

  const initDb = async () => {
    setIsDbLoading(true);
    addLog("Initializing database connection...", "info");
    try {
      const connected = await DatabaseService.checkConnection();
      setIsOnline(connected);

      if (connected) {
        addLog("MongoDB Connected. Fetching remote data...", "success");
        const [pRes, cRes, oRes, sRes] = await Promise.all([
          DatabaseService.getProducts(),
          DatabaseService.getCustomers(),
          DatabaseService.getOfficers(),
          DatabaseService.getSales()
        ]);

        setProducts(pRes.success ? pRes.data : INITIAL_PRODUCTS);
        setCustomers(cRes.success ? cRes.data : INITIAL_CUSTOMERS);
        setOfficers(oRes.success ? oRes.data : INITIAL_OFFICERS);
        setSales(sRes.success ? sRes.data : []);

        if (!pRes.success) addLog("Failed to fetch products from MongoDB, using initial data.", "error");
        else addLog("Products synced successfully.", "success");
      } else {
        addLog("Backend unreachable. Using Local Storage.", "error");
        setProducts(INITIAL_PRODUCTS);
        setCustomers(INITIAL_CUSTOMERS);
        setOfficers(INITIAL_OFFICERS);
        setSales([]);
      }
    } catch (err: any) {
      addLog(`Initialization Error: ${err.message}`, "error");
      setIsOnline(false);
    } finally {
      setIsDbLoading(false);
    }
  };

  useEffect(() => {
    const logged = localStorage.getItem('erp_logged_in') === 'true';
    setIsLoggedIn(logged);
    const l = localStorage.getItem('erp_lang') as Lang;
    if(l) setLang(l);
    initDb();
  }, []);

  // Sync Logic
  useEffect(() => {
    if (isDbLoading) return;

    const syncWithDb = async () => {
      if (isOnline) {
        setIsSyncing(true);
        addLog("Starting background sync to MongoDB...", "info");
        try {
          const results = await Promise.all([
            DatabaseService.saveProducts(products),
            DatabaseService.saveCustomers(customers),
            DatabaseService.saveOfficers(officers)
          ]);

          const allSuccess = results.every(r => r.success);
          if (allSuccess) {
            addLog("All data synced to MongoDB successfully.", "success");
          } else {
            addLog("Partial sync failure. Some data may only be local.", "error");
          }
        } catch (err: any) {
          addLog(`Sync error: ${err.message}`, "error");
          setIsOnline(false);
        } finally {
          setIsSyncing(false);
        }
      }
    };

    const timeout = setTimeout(syncWithDb, 10000); // 10s debounce for sync
    return () => clearTimeout(timeout);
  }, [products, customers, officers, isDbLoading, isOnline]);

  const addSale = async (newSale: Sale) => {
    setSales(prev => [...prev, newSale]);
    setProducts(prev => prev.map(p => {
      const soldItem = newSale.items.find(si => si.productCode === p.code);
      if (soldItem) return { ...p, stock: p.stock - soldItem.quantity };
      return p;
    }));
    if (newSale.dueAmount !== 0) {
      setCustomers(prev => prev.map(c => {
        if (c.id === newSale.customerId) return { ...c, balance: c.balance - newSale.dueAmount };
        return c;
      }));
    }

    if (isOnline) {
      addLog(`Posting Sale Invoice #ABS-${newSale.invoiceNo} to MongoDB...`, "info");
      const res = await DatabaseService.addSale(newSale);
      if (res.success) addLog(`Invoice #ABS-${newSale.invoiceNo} recorded successfully.`, "success");
      else addLog(`Invoice record failed. Saved locally.`, "error");
    }
  };

  const deleteSale = async (invoiceNo: string) => {
    const saleToDelete = sales.find(s => s.invoiceNo === invoiceNo);
    if (!saleToDelete) return;
    if (!confirm('Confirm deletion?')) return;

    setSales(prev => prev.filter(s => s.invoiceNo !== invoiceNo));
    if (isOnline) {
      addLog(`Deleting Invoice #ABS-${invoiceNo} from MongoDB...`, "info");
      const res = await DatabaseService.deleteSale(invoiceNo);
      if (res.success) {
        addLog(`Invoice #ABS-${invoiceNo} deleted from remote.`, "success");
        initDb(); // Refresh to reconcile stocks
      } else {
        addLog(`Delete failed remotely. Updated locally.`, "error");
      }
    }
  };

  const runSmartAnalysis = async () => {
    setIsAnalyzing(true);
    addLog("Requesting AI Business Analysis from Gemini...", "info");
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Analyze this product data for ${companyName}: ${JSON.stringify(products)}. Generate a strategic report in ${lang}. Focus on stock health and pricing strategy.`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      setAiAnalysis(response.text || "No response.");
      addLog("AI Analysis report generated.", "success");
    } catch (err: any) {
      addLog(`AI Error: ${err.message}`, "error");
      setAiAnalysis("Analysis failed.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  if (!isLoggedIn) {
    return (
      <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
        <LoginPage onLogin={() => { setIsLoggedIn(true); localStorage.setItem('erp_logged_in', 'true'); }} />
      </LanguageContext.Provider>
    );
  }

  if (isDbLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white gap-6">
        <Loader2 className="animate-spin text-[#722f37]" size={64} />
        <h2 className="text-xl font-black tracking-widest uppercase">Initializing Monolith API...</h2>
        <div className="w-64 h-1 bg-slate-800 rounded-full overflow-hidden">
          <div className="h-full bg-[#722f37] animate-progress-indefinite"></div>
        </div>
      </div>
    );
  }

  return (
    <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
      <div className="flex min-h-screen bg-slate-50">
        <Sidebar currentView={view} setView={setView} isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} />

        <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
          <header className="h-20 flex items-center justify-between px-8 bg-white border-b border-slate-200 no-print">
            <div className="flex items-center gap-4">
              <button className="md:hidden p-2" onClick={() => setSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden md:block">
                <h2 className="text-xl font-black text-[#722f37]">{companyName}</h2>
                <button 
                  onClick={() => setShowSyncLog(!showSyncLog)}
                  className={`flex items-center gap-1.5 px-3 py-1 rounded-full border text-[8px] font-black uppercase transition-all ${isOnline ? 'bg-slate-900 border-slate-800 text-white hover:bg-black' : 'bg-rose-50 border-rose-100 text-rose-600'}`}
                >
                  {isOnline ? (isSyncing ? 'Syncing...' : 'Atlas Connected') : 'Local Mode'}
                  {isOnline && <RefreshCw size={10} className={isSyncing ? 'animate-spin' : ''} />}
                  <History size={10} className="ml-1 opacity-50" />
                </button>
              </div>
            </div>

            <div className="flex gap-4">
              <button onClick={runSmartAnalysis} className="bg-slate-900 text-emerald-400 px-5 py-2.5 rounded-2xl text-xs font-black flex items-center gap-2 shadow-lg active:scale-95 transition-all"><BrainCircuit size={18} /> AI Analysis</button>
              <button onClick={() => { setLang(lang === 'EN' ? 'BN' : 'EN'); localStorage.setItem('erp_lang', lang === 'EN' ? 'BN' : 'EN'); }} className="bg-[#722f37] text-white px-5 py-2.5 rounded-2xl text-xs font-black flex items-center gap-2 shadow-xl shadow-rose-950/20 active:scale-95 transition-all"><Languages size={18} /> {t('toggleLang')}</button>
            </div>
          </header>

          <main className="flex-1 overflow-y-auto p-6 md:p-10 relative">
            {/* Sync History Overlay */}
            {showSyncLog && (
              <div className="absolute top-2 right-10 w-96 max-h-[400px] bg-white border border-slate-200 shadow-2xl rounded-3xl z-[100] flex flex-col overflow-hidden animate-in slide-in-from-top-4">
                <div className="bg-slate-900 p-4 text-white flex justify-between items-center shrink-0">
                  <div className="flex items-center gap-2">
                    <History size={18} className="text-[#722f37]" />
                    <span className="text-xs font-black uppercase tracking-widest">{t('syncStatus')}</span>
                  </div>
                  <div className="flex items-center gap-3">
                    <button onClick={initDb} className="p-1 hover:bg-slate-800 rounded-lg transition-colors"><RefreshCw size={14} /></button>
                    <button onClick={() => setShowSyncLog(false)} className="p-1 hover:bg-slate-800 rounded-lg transition-colors"><X size={18} /></button>
                  </div>
                </div>
                <div className="flex-1 overflow-y-auto p-2 space-y-1 bg-slate-50">
                  {syncLogs.length === 0 ? (
                    <div className="p-8 text-center text-slate-400 text-[10px] font-bold uppercase">No logs recorded yet</div>
                  ) : (
                    syncLogs.map(log => (
                      <div key={log.id} className={`p-3 rounded-xl border flex items-start gap-3 ${log.type === 'success' ? 'bg-emerald-50 border-emerald-100' : log.type === 'error' ? 'bg-rose-50 border-rose-100' : 'bg-white border-slate-100'}`}>
                        {log.type === 'success' && <CheckCircle2 size={14} className="text-emerald-500 mt-0.5 shrink-0" />}
                        {log.type === 'error' && <AlertCircle size={14} className="text-rose-500 mt-0.5 shrink-0" />}
                        {log.type === 'info' && <RefreshCw size={14} className="text-blue-500 mt-0.5 shrink-0 animate-spin" />}
                        <div className="flex-1 min-w-0">
                          <p className={`text-[10px] font-bold leading-tight ${log.type === 'success' ? 'text-emerald-900' : log.type === 'error' ? 'text-rose-900' : 'text-slate-700'}`}>{log.message}</p>
                          <p className="text-[8px] font-black text-slate-400 mt-1 uppercase opacity-50">{log.timestamp}</p>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            )}

            {view === 'dashboard' && <Dashboard products={products} sales={sales} customers={customers} onDeleteSale={deleteSale} />}
            {view === 'sales' && <SalesEntry products={products} customers={customers} officers={officers} onAddSale={addSale} />}
            {view === 'products' && <ProductList products={products} setProducts={setProducts} onAnalyze={runSmartAnalysis} />}
            {view === 'stock' && <StockManagement products={products} setProducts={setProducts} />}
            {view === 'customers' && <CustomerList customers={customers} setCustomers={setCustomers} />}
            {view === 'officers' && <OfficerList officers={officers} setOfficers={setOfficers} />}
            {view === 'reports' && <Reports sales={sales} products={products} officers={officers} customers={customers} onDeleteSale={deleteSale} />}
          </main>
        </div>
      </div>

      {(isAnalyzing || aiAnalysis) && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl flex flex-col h-[80vh]">
            <div className="bg-slate-900 p-8 text-white flex justify-between items-center">
              <div className="flex items-center gap-3">
                <Sparkles size={24} className="text-emerald-400" />
                <h2 className="text-2xl font-black">{t('analysisDone')}</h2>
              </div>
              <button onClick={() => setAiAnalysis(null)} className="p-2 hover:bg-slate-800 rounded-full transition-colors"><X size={24} /></button>
            </div>
            <div className="flex-1 overflow-y-auto p-10 bg-slate-50">
              {isAnalyzing ? (
                <div className="h-full flex flex-col items-center justify-center gap-4 text-[#722f37]">
                  <Loader2 className="animate-spin" size={48} />
                  <p className="font-black uppercase tracking-widest text-xs">{t('analysisWait')}</p>
                </div>
              ) : (
                <div className="whitespace-pre-wrap leading-relaxed prose prose-slate max-w-none text-slate-700 font-medium bg-white p-8 rounded-3xl border border-slate-200">
                  {aiAnalysis}
