            <div className="p-6 bg-slate-50 border-t border-slate-200 flex justify-center">
              <button onClick={() => setAiAnalysis(null)} className="px-8 py-3 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-black transition-all">Close Report</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

