export default function App() {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [view, setView] = useState<View>('dashboard');
  const [lang, setLang] = useState<Lang>('BN');
  const [isDbLoading, setIsDbLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isOnline, setIsOnline] = useState(false);

  const [syncLogs, setSyncLogs] = useState<SyncLogEntry[]>([]);
  const [showSyncLog, setShowSyncLog] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [officers, setOfficers] = useState<Officer[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);

  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);

  const t = (key: string) => translations[lang][key] || key;
  const companyName = t('companyLabel');

  const addLog = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
    setSyncLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 50));
  };

  const checkStatus = async () => {
    const connected = await DatabaseService.checkConnection();
    if (connected !== isOnline) {
      setIsOnline(connected);
      if (connected) addLog("Database connection restored.", "success");
      else addLog("Connection to MongoDB lost.", "error");
    }
    return connected;
  };

  const initDb = async () => {
    setIsDbLoading(true);
    addLog("Initializing database connection...", "info");
    try {
      const connected = await checkStatus();

      if (connected) {
        addLog("MongoDB Connected (Stable API V1). Fetching remote data...", "success");
        const [pRes, cRes, oRes, sRes] = await Promise.all([
          DatabaseService.getProducts(),
          DatabaseService.getCustomers(),
          DatabaseService.getOfficers(),
          DatabaseService.getSales()
        ]);

        setProducts(pRes.success ? pRes.data : INITIAL_PRODUCTS);
        setCustomers(cRes.success ? cRes.data : INITIAL_CUSTOMERS);
        setOfficers(oRes.success ? oRes.data : INITIAL_OFFICERS);
        setSales(sRes.success ? sRes.data : []);

        if (!pRes.success) addLog("Failed to fetch products from MongoDB, using initial data.", "error");
        else addLog("Core data fetched successfully.", "success");
      } else {
        addLog("Backend unreachable. Using Local Storage fallback.", "error");
        setProducts(INITIAL_PRODUCTS);
        setCustomers(INITIAL_CUSTOMERS);
        setOfficers(INITIAL_OFFICERS);
        setSales([]);
      }
    } catch (err: any) {
      addLog(`Initialization Error: ${err.message}`, "error");
      setIsOnline(false);
    } finally {
      setIsDbLoading(false);
    }
  };

  useEffect(() => {
    const logged = localStorage.getItem('erp_logged_in') === 'true';
    setIsLoggedIn(logged);
    const l = localStorage.getItem('erp_lang') as Lang;
    if(l) setLang(l);
    initDb();

    // Auto-ping every 30 seconds
    const interval = setInterval(checkStatus, 30000);
    return () => clearInterval(interval);
  }, []);

  // Sync Logic
  useEffect(() => {
    if (isDbLoading) return;

    const syncWithDb = async () => {
      if (isOnline) {
        setIsSyncing(true);
        addLog("Starting background sync...", "info");
        try {
          const results = await Promise.all([
            DatabaseService.saveProducts(products),
            DatabaseService.saveCustomers(customers),
            DatabaseService.saveOfficers(officers)
          ]);

          if (results.every(r => r.success)) {
            addLog("Global sync completed.", "success");
          } else {
            addLog("Sync encountered issues on some collections.", "error");
          }
        } catch (err: any) {
          addLog(`Sync error: ${err.message}`, "error");
          setIsOnline(false);
        } finally {
          setIsSyncing(false);
        }
      }
    };

    const timeout = setTimeout(syncWithDb, 15000); // Debounced sync
    return () => clearTimeout(timeout);
  }, [products, customers, officers, isDbLoading, isOnline]);

  const addSale = async (newSale: Sale) => {
    setSales(prev => [...prev, newSale]);
    // Local stock update
    setProducts(prev => prev.map(p => {
      const soldItem = newSale.items.find(si => si.productCode === p.code);
      if (soldItem) return { ...p, stock: p.stock - soldItem.quantity };
      return p;
    }));

    if (isOnline) {
      addLog(`Sending Invoice #ABS-${newSale.invoiceNo} to MongoDB...`, "info");
      const res = await DatabaseService.addSale(newSale);
      if (res.success) addLog(`Invoice #ABS-${newSale.invoiceNo} saved to Atlas.`, "success");
      else addLog(`Remote save failed. Data kept locally.`, "error");
    }
  };

  const deleteSale = async (invoiceNo: string) => {
    if (!confirm('Are you sure you want to delete this invoice?')) return;
    setSales(prev => prev.filter(s => s.invoiceNo !== invoiceNo));

    if (isOnline) {
      addLog(`Requesting deletion of #ABS-${invoiceNo} from MongoDB...`, "info");
      const res = await DatabaseService.deleteSale(invoiceNo);
      if (res.success) {
        addLog(`Invoice #ABS-${invoiceNo} purged from remote.`, "success");
        initDb(); // Re-fetch to reconcile balances
      } else {
        addLog(`Remote delete failed.`, "error");
      }
    }
  };

  const runSmartAnalysis = async () => {
    setIsAnalyzing(true);
    addLog("Requesting Gemini AI analysis...", "info");
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Analyze this product data for ${companyName}: ${JSON.stringify(products)}. Generate a strategic report in ${lang}. Focus on stock health and pricing strategy.`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      setAiAnalysis(response.text || "No response.");
      addLog("AI Business Insight generated.", "success");
    } catch (err: any) {
      addLog(`AI Analysis Error: ${err.message}`, "error");
      setAiAnalysis("Analysis failed.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  if (!isLoggedIn) {
    return (
      <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
        <LoginPage onLogin={() => { setIsLoggedIn(true); localStorage.setItem('erp_logged_in', 'true'); }} />
      </LanguageContext.Provider>
    );
  }

  if (isDbLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white gap-6">
        <div className="relative">
          <Loader2 className="animate-spin text-[#722f37]" size={80} />
          <Database className="absolute inset-0 m-auto text-white/20" size={32} />
        </div>
        <div className="text-center space-y-2">
          <h2 className="text-2xl font-black tracking-[0.2em] uppercase">ABS FEED ERP</h2>
          <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Establishing Secure MongoDB Tunnel...</p>
        </div>
      </div>
    );
  }

  return (
    <LanguageContext.Provider value={{ lang, setLang, t, companyName }}>
      <div className="flex min-h-screen bg-slate-50">
        <Sidebar currentView={view} setView={setView} isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} />

        <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
          <header className="h-20 flex items-center justify-between px-8 bg-white border-b border-slate-200 no-print">
            <div className="flex items-center gap-6">
              <button className="md:hidden p-2" onClick={() => setSidebarOpen(true)}><Menu size={24} /></button>

              <div className="hidden md:block">
                <h2 className="text-xl font-black text-[#722f37] tracking-tight">{companyName}</h2>
              </div>

              {/* CONNECTION STATUS WIDGET */}
              <div 
                onClick={() => setShowSyncLog(!showSyncLog)}
                className={`flex items-center gap-3 px-4 py-2 rounded-2xl border transition-all cursor-pointer select-none ${isOnline ? 'bg-slate-900 border-slate-800 text-white shadow-lg' : 'bg-rose-50 border-rose-100 text-rose-600'}`}
              >
                <div className="relative flex h-3 w-3">
                  {isOnline && <span className={`animate-ping absolute inline-flex h-full w-full rounded-full ${isSyncing ? 'bg-amber-400' : 'bg-emerald-400'} opacity-75`}></span>}
                  <span className={`relative inline-flex rounded-full h-3 w-3 ${isOnline ? (isSyncing ? 'bg-amber-500' : 'bg-emerald-500') : 'bg-rose-500'}`}></span>
                </div>

                <div className="flex flex-col">
                  <span className="text-[10px] font-black uppercase leading-tight tracking-widest">
                    {isOnline ? t('dbLive') : t('dbOffline')}
                  </span>
                  <span className={`text-[8px] font-bold uppercase tracking-tighter opacity-70 flex items-center gap-1`}>
                    {isOnline ? (isSyncing ? 'Synchronizing Atlas...' : 'Cluster: rxywjg9') : 'Retrying Connection...'}
                    {isOnline && isSyncing && <RefreshCw size={8} className="animate-spin" />}
                  </span>
                </div>

                <div className="pl-2 border-l border-white/10 ml-1 opacity-50">
                   <Activity size={14} className={isSyncing ? 'text-amber-400 animate-pulse' : ''} />
                </div>
              </div>
            </div>

            <div className="flex gap-4">
              <button onClick={runSmartAnalysis} className="hidden lg:flex bg-slate-900 text-emerald-400 px-5 py-2.5 rounded-2xl text-xs font-black items-center gap-2 shadow-lg active:scale-95 transition-all"><BrainCircuit size={18} /> AI Analysis</button>
              <button onClick={() => { setLang(lang === 'EN' ? 'BN' : 'EN'); localStorage.setItem('erp_lang', lang === 'EN' ? 'BN' : 'EN'); }} className="bg-[#722f37] text-white px-5 py-2.5 rounded-2xl text-xs font-black flex items-center gap-2 shadow-xl shadow-rose-950/20 active:scale-95 transition-all"><Languages size={18} /> {t('toggleLang')}</button>
            </div>
          </header>

          <main className="flex-1 overflow-y-auto p-6 md:p-10 relative">
            {/* Sync History Log Overlay */}
            {showSyncLog && (
              <div className="absolute top-2 left-6 w-[400px] max-h-[500px] bg-white border border-slate-200 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.3)] rounded-[2.5rem] z-[100] flex flex-col overflow-hidden animate-in slide-in-from-top-4 duration-300">
                <div className="bg-slate-900 p-6 text-white flex justify-between items-center shrink-0">
                  <div className="flex items-center gap-3">
                    <History size={20} className="text-[#722f37]" />
                    <div>
                       <span className="text-xs font-black uppercase tracking-widest block leading-tight">{t('syncStatus')}</span>
                       <span className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">MongoDB Atlas Monitor</span>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <button onClick={initDb} className="p-2 hover:bg-slate-800 rounded-xl transition-colors"><RefreshCw size={16} /></button>
                    <button onClick={() => setShowSyncLog(false)} className="p-2 hover:bg-slate-800 rounded-xl transition-colors"><X size={20} /></button>
                  </div>
                </div>
                <div className="flex-1 overflow-y-auto p-4 space-y-2 bg-slate-50">
                  {syncLogs.length === 0 ? (
                    <div className="p-12 text-center">
                       <Database size={40} className="mx-auto text-slate-200 mb-2" />
                       <p className="text-slate-400 text-[10px] font-bold uppercase">No data operations recorded</p>
                    </div>
                  ) : (
                    syncLogs.map(log => (
                      <div key={log.id} className={`p-4 rounded-2xl border flex items-start gap-4 shadow-sm ${log.type === 'success' ? 'bg-emerald-50 border-emerald-100' : log.type === 'error' ? 'bg-rose-50 border-rose-100' : 'bg-white border-slate-100'}`}>
                        <div className="mt-1">
                          {log.type === 'success' && <CheckCircle2 size={16} className="text-emerald-500" />}
                          {log.type === 'error' && <AlertCircle size={16} className="text-rose-500" />}
                          {log.type === 'info' && <Loader2 size={16} className="text-blue-500 animate-spin" />}
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className={`text-[11px] font-bold leading-tight ${log.type === 'success' ? 'text-emerald-900' : log.type === 'error' ? 'text-rose-900' : 'text-slate-700'}`}>{log.message}</p>
                          <p className="text-[9px] font-black text-slate-400 mt-2 uppercase opacity-60 flex justify-between">
                            <span>{log.timestamp}</span>
                            <span className="text-slate-300">AUTO-SYNC</span>
                          </p>
                        </div>
                      </div>
                    ))
                  )}
                </div>
                <div className="p-4 bg-white border-t border-slate-100 text-center">
                   <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Connected Cluster: Cluster0.rxywjg9</p>
                </div>
              </div>
            )}

            {view === 'dashboard' && <Dashboard products={products} sales={sales} customers={customers} onDeleteSale={deleteSale} />}
            {view === 'sales' && <SalesEntry products={products} customers={customers} officers={officers} onAddSale={addSale} />}
            {view === 'products' && <ProductList products={products} setProducts={setProducts} onAnalyze={runSmartAnalysis} />}
            {view === 'stock' && <StockManagement products={products} setProducts={setProducts} />}
            {view === 'customers' && <CustomerList customers={customers} setCustomers={setCustomers} />}
            {view === 'officers' && <OfficerList officers={officers} setOfficers={setOfficers} />}
            {view === 'reports' && <Reports sales={sales} products={products} officers={officers} customers={customers} onDeleteSale={deleteSale} />}
          </main>
        </div>
      </div>

      {/* MODALS */}
      {(isAnalyzing || aiAnalysis) && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl flex flex-col h-[80vh]">
            <div className="bg-slate-900 p-8 text-white flex justify-between items-center">
              <div className="flex items-center gap-3">
                <Sparkles size={24} className="text-emerald-400" />
                <h2 className="text-2xl font-black uppercase tracking-tight">{t('analysisDone')}</h2>
              </div>
              <button onClick={() => setAiAnalysis(null)} className="p-2 hover:bg-slate-800 rounded-full transition-colors"><X size={24} /></button>
            </div>
            <div className="flex-1 overflow-y-auto p-10 bg-slate-50">
              {isAnalyzing ? (
                <div className="h-full flex flex-col items-center justify-center gap-6">
                  <div className="relative">
                    <Loader2 className="animate-spin text-emerald-500" size={60} />
                    <BrainCircuit className="absolute inset-0 m-auto text-emerald-300" size={24} />
