            </div>
            <div className="p-8 bg-slate-50 border-t border-slate-200 flex justify-center shrink-0">
              <button onClick={() => setAiAnalysis(null)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-black transition-all shadow-xl shadow-slate-200 active:scale-95">Close Business Report</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

