                  ) : (
                    syncLogs.map(log => (
                      <div key={log.id} className={`p-4 rounded-2xl border flex items-start gap-4 shadow-sm ${log.type === 'success' ? 'bg-emerald-50 border-emerald-100' : log.type === 'error' ? 'bg-rose-50 border-rose-100' : 'bg-white border-slate-100'}`}>
                        <div className="mt-1">
                          {log.type === 'success' && <CheckCircle2 size={16} className="text-emerald-500" />}
                          {log.type === 'error' && <AlertCircle size={16} className="text-rose-500" />}
                          {log.type === 'info' && <Loader2 size={16} className="text-blue-500 animate-spin" />}
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className={`text-[11px] font-bold leading-tight ${log.type === 'success' ? 'text-emerald-900' : log.type === 'error' ? 'text-rose-900' : 'text-slate-700'}`}>{log.message}</p>
                          <p className="text-[9px] font-black text-slate-400 mt-2 uppercase opacity-60 flex justify-between">
                            <span>{log.timestamp}</span>
                            <span className="text-slate-300">AUTO-SYNC</span>
                          </p>
                        </div>
                      </div>
                    ))
                  )}
                </div>
                <div className="p-4 bg-white border-t border-slate-100 text-center">
                   <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Connected Cluster: Cluster0.rxywjg9</p>
                </div>
              </div>
            )}

            {view === 'dashboard' && <Dashboard products={products} sales={sales} customers={customers} officers={officers} onDeleteSale={deleteSale} />}
            {view === 'sales' && <SalesEntry products={products} customers={customers} officers={officers} onAddSale={addSale} />}
            {view === 'products' && <ProductList products={products} setProducts={setProducts} onAnalyze={runSmartAnalysis} />}
            {view === 'stock' && <StockManagement products={products} setProducts={setProducts} />}
            {view === 'customers' && <CustomerList customers={customers} sales={sales} officers={officers} setCustomers={setCustomers} setSales={setSales} />}
            {view === 'officers' && <OfficerList officers={officers} sales={sales} setOfficers={setOfficers} setSales={setSales} />}
            {view === 'reports' && <Reports sales={sales} products={products} officers={officers} customers={customers} onDeleteSale={deleteSale} />}
          </main>
        </div>
      </div>

      {/* MODALS */}
      {(isAnalyzing || aiAnalysis) && (
