            <div className="bg-slate-900 p-8 text-white flex justify-between items-center">
              <div className="flex items-center gap-3">
                <Sparkles size={24} className="text-emerald-400" />
                <h2 className="text-2xl font-black uppercase tracking-tight">{t('analysisDone')}</h2>
              </div>
              <button onClick={() => setAiAnalysis(null)} className="p-2 hover:bg-slate-800 rounded-full transition-colors"><X size={24} /></button>
            </div>
            <div className="flex-1 overflow-y-auto p-10 bg-slate-50">
              {isAnalyzing ? (
                <div className="h-full flex flex-col items-center justify-center gap-6">
                  <div className="relative">
                    <Loader2 className="animate-spin text-emerald-500" size={60} />
                    <BrainCircuit className="absolute inset-0 m-auto text-emerald-300" size={24} />
                  </div>
                  <p className="font-black uppercase tracking-widest text-xs text-slate-500">{t('analysisWait')}</p>
                </div>
              ) : (
                <div className="whitespace-pre-wrap leading-relaxed prose prose-slate max-w-none text-slate-700 font-medium bg-white p-10 rounded-[2.5rem] border border-slate-200 shadow-sm">
                  {aiAnalysis}
                </div>
              )}
            </div>
            <div className="p-8 bg-slate-50 border-t border-slate-200 flex justify-center shrink-0">
              <button onClick={() => setAiAnalysis(null)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-black transition-all shadow-xl shadow-slate-200 active:scale-95">Close Business Report</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useContext } from 'react';
import { Customer, Sale, Officer } from '../types';
import { Search, Plus, MapPin, Phone, Building, User, X, Printer, FileText, Calendar, UserCheck, ShieldCheck, Receipt, PieChart, Activity, Mail, Edit, CheckCircle, Save, AlertCircle } from 'lucide-react';
import { LanguageContext } from '../App';

interface CustomerListProps {
  customers: Customer[];
  sales: Sale[];
  officers: Officer[];
  setCustomers: React.Dispatch<React.SetStateAction<Customer[]>>;
  setSales: React.Dispatch<React.SetStateAction<Sale[]>>;
}

const CustomerList: React.FC<CustomerListProps> = ({ customers, sales, officers, setCustomers, setSales }) => {
  const { t, lang, companyName } = useContext(LanguageContext)!;
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingCustomer, setEditingCustomer] = useState<Customer | null>(null);
  const [viewStatement, setViewStatement] = useState<Customer | null>(null);

  const [formData, setFormData] = useState<Partial<Customer>>({
    type: 'Dealer',
    creditLimit: 0,
    balance: 0
  });

  const handleOpenModal = (c?: Customer) => {
    if (c) {
      setEditingCustomer(c);
      setFormData({ ...c });
    } else {
      setEditingCustomer(null);
      setFormData({
        id: `C${Math.floor(Math.random() * 1000).toString().padStart(3, '0')}`,
        name: '', 
        companyName: '', 
        address: '', 
        mobile: '', 
        type: 'Dealer', 
        creditLimit: 500000, 
        balance: 0
      });
    }
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.id) return;

    // Check ID uniqueness if it's a new ID
    if (!editingCustomer || (editingCustomer && editingCustomer.id !== formData.id)) {
      const exists = customers.some(c => c.id === formData.id);
      if (exists) {
        alert(lang === 'BN' ? "এই আইডি ইতিমধ্যে অন্য কাস্টমারের জন্য ব্যবহৃত হচ্ছে!" : "This ID is already used by another customer!");
        return;
      }
    }

    if (editingCustomer) {
      const oldId = editingCustomer.id;
      const newId = formData.id!;

      // Cascading Update for Sales records if ID changed
      if (oldId !== newId) {
        setSales(prev => prev.map(s => s.customerId === oldId ? { ...s, customerId: newId } : s));
      }

      // Update customer object
      setCustomers(prev => prev.map(c => c.id === oldId ? { ...c, ...formData as Customer } : c));
    } else {
      // Add new customer
      setCustomers(prev => [...prev, formData as Customer]);
    }
    setShowModal(false);
    setEditingCustomer(null);
  };

  const filtered = customers.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.companyName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getCustomerSales = (customerId: string) => {
    return sales.filter(s => s.customerId === customerId).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 no-print">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">{lang === 'BN' ? 'কাস্টমার ও ডিলার' : 'Customer Network'}</h1>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Partnership & Credit Management</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
