              <span className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest ${customer.type === 'Dealer' ? 'bg-purple-100 text-purple-700' : 'bg-rose-100 text-[#722f37]'}`}>
                {customer.type}
