                <div className="flex gap-2">
                  <button onClick={() => window.print()} className="px-6 py-2.5 bg-white text-[#722f37] hover:bg-rose-50 rounded-xl transition-all flex items-center gap-2 font-black text-[10px] uppercase shadow-lg">
                    <Printer size={18} /> {lang === 'BN' ? 'প্রিন্ট' : 'Print Statement'}
