                </div>
             </div>

             <div className="flex-1 p-10 space-y-10 overflow-y-auto print-p-0 print-m-0 invoice-content">
                <div className="border-b-2 border-[#722f37] pb-8 shrink-0">
                  <div className="text-center mb-6">
                    <h1 className="text-3xl font-black text-[#722f37] uppercase leading-none">{companyName}</h1>
                    <p className="text-xs text-slate-600 font-bold uppercase tracking-widest mt-2">(A Sister Concern of AHYAN GROUP)</p>
                  </div>
                  <div className="grid grid-cols-2 gap-8 text-[10px]">
                    <div className="space-y-1 font-semibold text-slate-500 italic">
                      <p className="font-black text-[#722f37] uppercase not-italic">Head Office:</p>
